export const DATA = [
  /* ====== 第 1 個月：JS / TS 基礎 ====== */
  { m:1,w:1,d:1,t:"觀念題",q:"map 和 forEach 有什麼差異？什麼情況該用哪一個？",a:"<b>map</b> 會回傳一個<b>新陣列</b>，適合「把資料轉成另一種形狀」，例如把 API 資料轉成畫面要的格式。<b>forEach</b> 沒有回傳值，只是逐一執行動作，適合純粹的副作用（如 console、累加到外部變數）。後台開發中 90% 的資料轉換都該用 map / filter / reduce，因為可以串接且不改動原始資料。" , opts: ["map 會回傳新陣列，適合資料轉換；forEach 無回傳值，適合執行副作用","forEach 會回傳新陣列，map 只用來執行副作用，兩者可以互換使用","map 和 forEach 功能完全相同，只是語法風格不同","map 適合有副作用的操作，forEach 適合需要回傳值的資料轉換"], ans: 0},
  { m:1,w:1,d:2,t:"程式題",q:"有商品陣列 products = [{name:'A', price:100, stock:0}, {name:'B', price:250, stock:3}, {name:'C', price:80, stock:5}]。請用 filter 和 map 取出「有庫存的商品名稱」陣列。",a:"<pre>const names = products\n  .filter(p => p.stock > 0)\n  .map(p => p.name);\n// ['B', 'C']</pre>先 filter 篩出符合條件的物件，再 map 轉成需要的欄位。這個「先篩選、再轉換」的組合是後台表格資料處理最常見的模式。" , opts: ["products.map(p => p.name).filter(p => p.stock > 0)","products.filter(p => p.stock > 0).map(p => p.name)","products.reduce((acc, p) => p.stock > 0 ? [...acc, p.name] : acc, [])","products.filter(p => p.stock >= 0).map(p => p.name)"], ans: 1},
  { m:1,w:1,d:3,t:"程式題",q:"延續昨天的 products，請用 reduce 計算「有庫存商品的總價值」（price × stock 加總）。",a:"<pre>const total = products\n  .filter(p => p.stock > 0)\n  .reduce((sum, p) => sum + p.price * p.stock, 0);\n// 250*3 + 80*5 = 1150</pre><b>reduce 重點：</b>第二個參數 <code>0</code> 是初始值，一定要給；callback 的第一個參數是累加器，每一輪要 return 出去，下一輪才接得到。" , opts: ["products.reduce((sum, p) => sum + p.price * p.stock, 0)","products.filter(p => p.stock > 0).reduce((sum, p) => sum + p.price, 0)","products.filter(p => p.stock > 0).reduce((sum, p) => sum + p.price * p.stock, 0)","products.filter(p => p.stock > 0).map(p => p.price * p.stock).reduce((a, b) => a + b)"], ans: 2},
  { m:1,w:1,d:4,t:"程式題",q:"API 回傳 res = { data: { list: [...], total: 20 } }，但有時候 data 可能是 null。請用解構 + 預設值安全地取出 list 和 total。",a:"<pre>const { list = [], total = 0 } = res.data ?? {};</pre>兩層防護：<code>??</code> 在 data 是 null / undefined 時退回空物件，解構的 <code>= []</code> 和 <code>= 0</code> 在屬性不存在時給預設值。這樣畫面渲染 <code>list.map(...)</code> 就不會炸掉。" , opts: ["const { list, total } = res.data; 直接解構不需要預設值","const list = res.data?.list; const total = res.data?.total; 分別取值","const { list = [], total = 0 } = res.data ?? {};","const { list = [], total = 0 } = res.data || null;"], ans: 2},
  { m:1,w:1,d:5,t:"觀念題",q:"展開運算子 {...obj} 是深拷貝還是淺拷貝？如果物件裡還有巢狀物件，要怎麼真正複製一份？",a:"<code>{...obj}</code> 是<b>淺拷貝</b>：第一層是新的，但巢狀物件仍指向同一個記憶體位置，改了會互相影響。需要深拷貝時：<pre>const copy = structuredClone(obj); // 現代瀏覽器內建\n// 舊方法：JSON.parse(JSON.stringify(obj))\n// 注意 JSON 法會丟失 undefined、function、Date 會變字串</pre>面試常考：表單編輯 Modal 帶入資料時若用淺拷貝，可能改到列表的原始資料。" , opts: ["{...obj} 是深拷貝，所有層級包含巢狀物件都會被完整複製","{...obj} 是淺拷貝，第一層為新物件，巢狀物件仍共用記憶體；深拷貝用 structuredClone(obj)","{...obj} 是淺拷貝，可以用 Object.assign({}, obj) 達成深拷貝","{...obj} 是淺拷貝，深拷貝只能透過 JSON.parse(JSON.stringify(obj)) 實現"], ans: 1},
  { m:1,w:2,d:1,t:"觀念題",q:"Promise 有哪三種狀態？狀態之間怎麼轉換？",a:"<ul><li><b>pending</b>（進行中）：初始狀態</li><li><b>fulfilled</b>（成功）：呼叫 resolve 後</li><li><b>rejected</b>（失敗）：呼叫 reject 或拋出錯誤後</li></ul>狀態<b>只能轉換一次</b>且不可逆：pending → fulfilled 或 pending → rejected。fulfilled 走 <code>.then</code>，rejected 走 <code>.catch</code>。" , opts: ["pending、running、done，狀態可以雙向轉換","idle、loading、settled，settled 可再分為成功或失敗","pending、fulfilled、rejected，狀態只能轉換一次且不可逆","pending、resolved、rejected，resolved 和 fulfilled 是不同的狀態"], ans: 2},
  { m:1,w:2,d:2,t:"程式題",q:"把這段 .then 寫法改成 async / await：<br><code>fetch('/api/users').then(r => r.json()).then(data => console.log(data))</code>",a:"<pre>async function loadUsers() {\n  const res = await fetch('/api/users');\n  const data = await res.json();\n  console.log(data);\n}</pre><b>兩個重點：</b>await 只能在 async function 裡用；<code>res.json()</code> 本身也回傳 Promise，所以也要 await。" , opts: ["async function loadUsers() { const data = await fetch('/api/users').json(); console.log(data); }","function loadUsers() { const res = await fetch('/api/users'); const data = await res.json(); console.log(data); }","async function loadUsers() { const res = await fetch('/api/users'); const data = await res.json(); console.log(data); }","async function loadUsers() { await fetch('/api/users').then(r => r.json()).then(data => console.log(data)); }"], ans: 2},
  { m:1,w:2,d:3,t:"程式題",q:"幫昨天的 loadUsers 加上完整的錯誤處理：API 失敗（HTTP 4xx/5xx）和網路錯誤都要能接到。",a:"<pre>async function loadUsers() {\n  try {\n    const res = await fetch('/api/users');\n    if (!res.ok) {\n      throw new Error('HTTP ' + res.status);\n    }\n    return await res.json();\n  } catch (err) {\n    console.error('載入失敗:', err.message);\n    throw err;\n  }\n}</pre><b>關鍵：</b>fetch 收到 404/500 <b>不會</b>自動 reject，要自己檢查 <code>res.ok</code>。" , opts: ["用 .catch() 在 Promise 鏈結尾捕捉錯誤，HTTP 錯誤會自動被偵測到","用 try/catch 包住，並在 fetch 後檢查 res.ok，若 !res.ok 則 throw new Error","用 try/catch 包住即可，fetch 本身會自動拋出 HTTP 4xx/5xx 錯誤","只需檢查 res.status === 200，其他狀態碼都當作網路錯誤處理"], ans: 1},
  { m:1,w:2,d:4,t:"程式題",q:"頁面載入時要同時打「使用者資料」和「訂單列表」兩支互不相依的 API。怎麼寫最有效率？",a:"<pre>const [user, orders] = await Promise.all([\n  fetchUser(),\n  fetchOrders(),\n]);</pre>用 <b>Promise.all</b> 並行發出，總時間 = 最慢的那支，而不是兩支相加。注意：其中一支失敗整個會 reject；若希望「各自成敗互不影響」改用 <code>Promise.allSettled</code>。" , opts: ["依序 await fetchUser() 再 await fetchOrders()，確保執行順序正確","用 Promise.race([fetchUser(), fetchOrders()]) 取得最快回傳的結果","用 Promise.all([fetchUser(), fetchOrders()]) 同時發出請求並等待全部完成","把兩個 fetch 放在不同 useEffect 中分別執行，避免互相干擾"], ans: 2},
  { m:1,w:2,d:5,t:"觀念題",q:"以下程式的輸出順序是什麼？為什麼？<pre>console.log('1');\nsetTimeout(() => console.log('2'), 0);\nPromise.resolve().then(() => console.log('3'));\nconsole.log('4');</pre>",a:"<b>輸出：1 → 4 → 3 → 2</b><ul><li>同步程式先跑完：1、4</li><li>Promise.then 進<b>微任務佇列</b>，同步結束後立刻執行：3</li><li>setTimeout 進<b>宏任務佇列</b>，要等微任務清空才輪到：2</li></ul>event loop 基本順序：同步 → 微任務 → 宏任務。" , opts: ["1→2→3→4，同步程式碼和 setTimeout 都屬於宏任務，Promise 最後執行","1→4→2→3，同步先跑，setTimeout 比 Promise.then 優先執行","1→3→4→2，Promise.then 是同步的，會在下一行 console.log 之前執行","1→4→3→2，同步先跑完，微任務 Promise.then 接著，宏任務 setTimeout 最後"], ans: 3},
  { m:1,w:3,d:1,t:"觀念題",q:"TypeScript 的 type 和 interface 有什麼差異？實務上怎麼選？",a:"<ul><li><b>interface</b>：描述物件形狀，可以 extends 繼承、同名會自動合併</li><li><b>type</b>：更萬用，可以定義 union、交集、原始型別別名、函式型別</li></ul><b>實務選法：</b>物件結構用 interface 或 type 都可以，團隊統一就好；需要 union、組合型別時只能用 type。" , opts: ["type 和 interface 功能完全相同，只是語法偏好不同，沒有實質差異","interface 只能描述物件結構，type 可定義 union 等；interface 支援繼承與同名合併","type 支援繼承和同名合併，interface 適合定義 union","interface 效能比 type 好，所有情況都應優先使用 interface"], ans: 1},
  { m:1,w:3,d:2,t:"程式題",q:"用 union type 定義一個 API 請求狀態 Status，只允許 'idle'、'loading'、'success'、'error' 四種值，並寫一個變數使用它。",a:"<pre>type Status = 'idle' | 'loading' | 'success' | 'error';\n\nlet status: Status = 'idle';\nstatus = 'loading'; // OK\nstatus = 'done';    // ❌ 編譯錯誤</pre>這叫<b>字面值聯合型別</b>，比用 string 安全：打錯字、漏狀態編譯期就會抓到。" , opts: ["type Status = { idle: string; loading: string; success: string; error: string; }","enum Status { idle, loading, success, error }","type Status = 'idle' | 'loading' | 'success' | 'error';","interface Status { value: 'idle' | 'loading' | 'success' | 'error'; }"], ans: 2},
  { m:1,w:3,d:3,t:"程式題",q:"定義一個 User interface：id（數字）、name（字串）、email（字串）、phone（可有可無）。並示範安全地印出 phone 的長度。",a:"<pre>interface User {\n  id: number;\n  name: string;\n  email: string;\n  phone?: string;\n}\n\nconst u: User = { id: 1, name: 'Amy', email: 'a@x.com' };\nconsole.log(u.phone?.length ?? 0);</pre><code>?</code> 宣告可選屬性；存取時用<b>可選串連</b> <code>?.</code> 避免 undefined 報錯，再用 <code>??</code> 給預設值。" , opts: ["interface User { phone: string; }，存取用 u.phone.length","interface User { phone: string | undefined; }，存取用 u.phone!.length","interface User { phone?: string; }，存取用 u.phone?.length ?? 0","interface User { phone?: string | null; }，存取用 u.phone?.length || 0"], ans: 2},
  { m:1,w:3,d:4,t:"程式題",q:"後端分頁查詢 API 回傳 { code: 0, message: 'ok', data: { list: [...使用者], total: 100, page: 1 } }。請設計完整的 response 型別。",a:"<pre>interface User {\n  id: number;\n  name: string;\n  email: string;\n}\ninterface PageData {\n  list: User[];\n  total: number;\n  page: number;\n}\ninterface UserListResponse {\n  code: number;\n  message: string;\n  data: PageData;\n}</pre><b>設計原則：</b>由內往外拆，每一層一個 interface，欄位名稱完全照後端 response 對。" , opts: ["直接定義一個扁平的 UserListResponse，把所有欄位放在同一層","由內往外定義 User、PageData（含 list/total/page）、UserListResponse（含 code/message/data）","只需定義最外層的 UserListResponse，內部 data 用 any 型別即可","先定義 UserListResponse，再用 Pick 和 Omit 從中取出內層型別"], ans: 1},
  { m:1,w:3,d:5,t:"程式題",q:"昨天的 code / message / data 結構其實每支 API 都一樣，只有 data 不同。請用 generic 改寫成可重用的 ApiResponse&lt;T&gt;。",a:"<pre>interface ApiResponse&lt;T&gt; {\n  code: number;\n  message: string;\n  data: T;\n}\n\ntype UserListRes = ApiResponse&lt;PageData&gt;;\ntype UserDetailRes = ApiResponse&lt;User&gt;;\ntype DeleteRes = ApiResponse&lt;null&gt;;</pre><b>generic 的本質：</b>把「會變動的部分」變成型別參數 T。" , opts: ["為每支 API 分別定義獨立的 response interface，避免泛型增加複雜度","用 extends 讓所有 response interface 繼承同一個 BaseResponse","interface ApiResponse<T> { code: number; message: string; data: T; } 以泛型參數替換 data 型別","用 type ApiResponse = Record<string, unknown> 達到最大彈性"], ans: 2},
  { m:1,w:4,d:1,t:"程式題",q:"把這支 JS 函式加上完整型別（參數與回傳值）：<pre>async function getUser(id) {\n  const res = await fetch('/api/users/' + id);\n  return res.json();\n}</pre>",a:"<pre>async function getUser(id: number): Promise&lt;ApiResponse&lt;User&gt;&gt; {\n  const res = await fetch('/api/users/' + id);\n  if (!res.ok) throw new Error('HTTP ' + res.status);\n  return res.json() as Promise&lt;ApiResponse&lt;User&gt;&gt;;\n}</pre>async 函式的回傳型別一定是 <code>Promise&lt;...&gt;</code>。" , opts: ["async function getUser(id: string): Promise<any>","async function getUser(id: number): Promise<User>","async function getUser(id: number): Promise<ApiResponse<User>>","function getUser(id: number): ApiResponse<User>"], ans: 2},
  { m:1,w:4,d:2,t:"程式題",q:"設計一個「新增使用者」表單的型別 UserForm（name、email、role 限定 'admin' | 'user'、備註可選），並寫出表單初始值。",a:"<pre>type Role = 'admin' | 'user';\ninterface UserForm {\n  name: string;\n  email: string;\n  role: Role;\n  note?: string;\n}\nconst initialForm: UserForm = {\n  name: '',\n  email: '',\n  role: 'user',\n};</pre>" , opts: ["interface UserForm { name: string; email: string; role: string; note: string; }，初始值全部空字串","interface UserForm { name: string; email: string; role: 'admin'|'user'; note?: string; }，初始值 role 為 'user'","type UserForm = { name: string; email: string; role: 'admin'|'user'; note: string | null; }","interface UserForm { name?: string; email?: string; role?: 'admin'|'user'; note?: string; }，所有欄位都可選"], ans: 1},
  { m:1,w:4,d:3,t:"程式題",q:"定義一個 React 按鈕元件的 props 型別：text（字串）、onClick（點擊函式）、disabled（可選布林）、children 不需要。",a:"<pre>interface ButtonProps {\n  text: string;\n  onClick: () => void;\n  disabled?: boolean;\n}\nfunction MyButton({ text, onClick, disabled = false }: ButtonProps) {\n  return (\n    &lt;button onClick={onClick} disabled={disabled}&gt;{text}&lt;/button&gt;\n  );\n}</pre>" , opts: ["interface ButtonProps { text: string; onClick: Function; disabled: boolean; }","type ButtonProps = { label: string; handleClick: () => void; disabled?: boolean; }","interface ButtonProps { text: string; onClick: (e: MouseEvent) => void; disabled?: boolean; }","interface ButtonProps { text: string; onClick: () => void; disabled?: boolean; }"], ans: 3},
  { m:1,w:4,d:4,t:"程式題",q:"API 回傳的使用者資料中 lastLoginAt 可能是字串也可能是 null。請設計型別，並寫出畫面顯示邏輯（null 時顯示「從未登入」）。",a:"<pre>interface User {\n  id: number;\n  name: string;\n  lastLoginAt: string | null;\n}\nconst text = user.lastLoginAt ?? '從未登入';</pre><b>原則：</b>後端說「可能沒有值」的欄位，型別就誠實寫 <code>| null</code>，逼自己在畫面層處理空值。" , opts: ["lastLoginAt: string | undefined; 顯示：user.lastLoginAt || '從未登入'","lastLoginAt: string | null; 顯示：user.lastLoginAt ?? '從未登入'","lastLoginAt: string; 顯示：user.lastLoginAt === '' ? '從未登入' : user.lastLoginAt","lastLoginAt: string | null | undefined; 顯示：user.lastLoginAt ? user.lastLoginAt : '從未登入'"], ans: 1},
  { m:1,w:4,d:5,t:"任務題",q:"【本週任務】完成一個 TypeScript API 串接小練習：用任一免費 API（如 jsonplaceholder.typicode.com/users）做出「載入並顯示使用者列表」。",a:"<b>驗收清單：</b><ul><li>☐ 為 API response 定義了 interface（不是 any）</li><li>☐ 有一支獨立的 getUsers() 函式負責呼叫 API</li><li>☐ 有 try/catch 與 res.ok 檢查</li><li>☐ 畫面能顯示 loading 中、錯誤、與資料列表三種狀態</li><li>☐ 程式碼放上 GitHub，附簡短 README</li></ul>" , opts: ["只要能成功呼叫 API 並印出資料到 console 即可，型別用 any 也沒關係","須有獨立 getUsers() 函式，但 loading/error 狀態管理是進階功能可省略","用 interface 定義 API response 型別（非 any）、有獨立 getUsers()、有 try/catch 與 res.ok 檢查、畫面有三態","只需定義 User interface 並確保資料能顯示，錯誤處理可之後再補"], ans: 2},

  /* ====== 第 2 個月：React 主線 ====== */
  { m:2,w:1,d:1,t:"觀念題",q:"props 和 state 的差異是什麼？哪個可以被元件自己修改？",a:"<ul><li><b>props</b>：由父元件傳入，對子元件是<b>唯讀</b>的，子元件不能直接改</li><li><b>state</b>：元件自己擁有的資料，透過 setState 修改，改變會觸發重新渲染</li></ul>判斷原則：資料是「別人給我的」就是 props，「我自己管理、會隨互動改變的」就是 state。" , opts: ["props 和 state 都可以被元件自己修改，差別只在來源不同","props 由父元件傳入且唯讀，state 是元件自有並透過 setState 修改觸發重新渲染","state 由父元件傳入，props 是元件自己管理的資料","props 可以直接賦值修改，state 必須透過父元件更新"], ans: 1},
  { m:2,w:1,d:2,t:"程式題",q:"寫一個 StatusTag 元件：接收 props status（'active' | 'inactive'），active 顯示綠色「啟用」，inactive 顯示灰色「停用」。",a:"<pre>interface StatusTagProps {\n  status: 'active' | 'inactive';\n}\nfunction StatusTag({ status }: StatusTagProps) {\n  const isActive = status === 'active';\n  return (\n    &lt;span style={{ color: isActive ? 'green' : 'gray' }}&gt;\n      {isActive ? '啟用' : '停用'}\n    &lt;/span&gt;\n  );\n}</pre>" , opts: ["用 if/else 分別 return 兩個不同的 JSX 元素，各自帶上顏色和文字","透過 className 切換 CSS class，在樣式表中定義 active 和 inactive 兩種顏色","用三元運算子同時決定 style 的顏色與顯示文字，一次 return 單一 span","接收 status 後直接顯示字串，顏色由父元件的 CSS 負責"], ans: 2},
  { m:2,w:1,d:3,t:"觀念題",q:"state 是一個物件 form = { name: '', email: '' }。為什麼不能寫 form.name = 'Amy' 來更新？正確寫法是什麼？",a:"React 用 <b>Object.is 比較參考</b>來判斷 state 有沒有變。直接改屬性，物件參考沒變，React 不會重新渲染。正確做法是建立<b>新物件</b>：<pre>setForm({ ...form, name: 'Amy' });\n// 或函式式更新\nsetForm(prev => ({ ...prev, name: 'Amy' }));</pre>" , opts: ["直接修改屬性雖然有效，但需要額外呼叫 forceUpdate() 才能觸發渲染","React 會深層比較物件所有屬性，直接修改屬性仍可偵測到變化","React 以 Object.is 比較參考，直接改屬性物件參考不變，React 不會重新渲染","直接修改屬性會觸發渲染，但會跳過 shouldComponentUpdate 的檢查"], ans: 2},
  { m:2,w:1,d:4,t:"程式題",q:"做一個受控元件：input 輸入文字，下方即時顯示「你好，{輸入的名字}」。",a:"<pre>function Greeting() {\n  const [name, setName] = useState('');\n  return (\n    &lt;div&gt;\n      &lt;input\n        value={name}\n        onChange={(e) =&gt; setName(e.target.value)}\n      /&gt;\n      &lt;p&gt;你好，{name}&lt;/p&gt;\n    &lt;/div&gt;\n  );\n}</pre><b>受控元件</b> = input 的值由 state 控制（value + onChange 成對出現）。" , opts: ["只需設定 defaultValue 屬性，React 會自動追蹤輸入值的變化","value 與 onChange 成對出現，透過 state 控制輸入值並在 onChange 中更新 state","使用 ref 取得 input DOM 節點，在需要時手動讀取 value","在 onBlur 事件中更新 state，避免每次按鍵都觸發重新渲染"], ans: 1},
  { m:2,w:1,d:5,t:"觀念題",q:"列表渲染時為什麼要給 key？為什麼不建議用 index 當 key？",a:"key 幫助 React 在重新渲染時<b>辨認哪些項目是同一個</b>，做最小幅度更新。用 index 當 key 的問題：當列表<b>排序、刪除、插入</b>時，index 會對不上原本的項目，導致畫面錯亂。<b>正確做法：</b>用資料中穩定唯一的值，通常是後端給的 id。" , opts: ["key 只是為了效能最佳化，不影響畫面正確性，用 index 沒有問題","key 必須是數字類型，使用字串 id 會導致比對錯誤","key 幫助 React 辨認項目身份；用 index 當 key 在排序或增刪時會對不上原項目導致錯亂","key 只在清單有超過 100 筆資料時才需要設定，少量資料可以省略"], ans: 2},
  { m:2,w:2,d:1,t:"觀念題",q:"useEffect 的依賴陣列有三種寫法：不寫、[]、[a, b]。各代表什麼時候執行？",a:"<ul><li><b>不寫</b>：每次渲染後都執行</li><li><b>[]（空陣列）</b>：只在元件掛載後執行一次，常用於初始載入資料</li><li><b>[a, b]</b>：掛載後執行一次 + a 或 b 改變時再執行</li></ul>原則：effect 裡用到的外部變數，都應該誠實放進依賴陣列。" , opts: ["不寫只執行一次；[] 每次渲染後執行；[a,b] 只在 a 或 b 為 true 時執行","不寫每次渲染後執行；[] 只在掛載後執行一次；[a,b] 掛載後加上 a 或 b 改變時執行","不寫和 [] 效果相同，都只執行一次；[a,b] 在 a 和 b 同時改變時才執行","不寫從不執行；[] 每次渲染後執行；[a,b] 只在元件卸載時執行"], ans: 1},
  { m:2,w:2,d:2,t:"程式題",q:"寫一個元件：掛載時呼叫 getUsers() 載入列表，載入中顯示「載入中…」，完成後顯示人數。",a:"<pre>function UserCount() {\n  const [users, setUsers] = useState([]);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() =&gt; {\n    getUsers()\n      .then(res =&gt; setUsers(res.data.list))\n      .finally(() =&gt; setLoading(false));\n  }, []);\n\n  if (loading) return &lt;p&gt;載入中…&lt;/p&gt;;\n  return &lt;p&gt;共 {users.length} 位使用者&lt;/p&gt;;\n}</pre>" , opts: ["依賴陣列寫 [users]，確保 users 更新後自動重新載入","不寫依賴陣列，讓每次渲染都能取得最新資料","依賴陣列寫 [loading]，等 loading 狀態改變後再執行","依賴陣列寫 []（空陣列），只在元件掛載時執行一次"], ans: 3},
  { m:2,w:2,d:3,t:"觀念題",q:"useEffect 的 cleanup（return 的函式）是做什麼用的？舉兩個實際使用場景。",a:"cleanup 在<b>元件卸載前</b>以及<b>下一次 effect 執行前</b>被呼叫，用來收拾上一輪留下的東西。<b>場景：</b><ul><li>清除計時器：<code>return () =&gt; clearInterval(timer)</code></li><li>取消事件監聽：<code>return () =&gt; window.removeEventListener(...)</code></li><li>中止過期的 API 請求（AbortController），避免 race condition</li></ul>" , opts: ["cleanup 只在元件卸載時呼叫，用來清除整個元件的所有資源","cleanup 在每次 effect 執行前及元件卸載前呼叫，用來清除上一輪的計時器或事件監聽","cleanup 在元件掛載完成後立即呼叫，用來初始化清理工作","cleanup 只有在依賴陣列為空 [] 時才會被呼叫"], ans: 1},
  { m:2,w:2,d:4,t:"觀念題",q:"這段程式為什麼會造成無限迴圈？怎麼修？<pre>const [data, setData] = useState([]);\nuseEffect(() => {\n  fetchData().then(setData);\n});</pre>",a:"<b>原因：</b>沒寫依賴陣列 → 每次渲染後都執行 effect → setData 觸發重新渲染 → 又執行 effect → 無限循環。<b>修法：</b>加上空依賴陣列：<pre>useEffect(() =&gt; {\n  fetchData().then(setData);\n}, []); // 只在掛載時執行一次</pre>" , opts: ["fetchData 是非同步函式，useEffect 不支援非同步，必須改用 useLayoutEffect","setData 是非同步操作，前一次尚未完成就觸發下一次，導致競態條件","沒寫依賴陣列導致每次渲染都執行 effect，setData 觸發重新渲染，形成無限循環","useState 的初始值是陣列，與 fetchData 回傳的資料型別不符造成循環錯誤"], ans: 2},
  { m:2,w:2,d:5,t:"程式題",q:"完成一個列表元件的三狀態渲染：loading 顯示「載入中」、error 顯示錯誤訊息與重試按鈕、資料為空顯示「目前沒有資料」。",a:"<pre>if (loading) return &lt;p&gt;載入中…&lt;/p&gt;;\n\nif (error) return (\n  &lt;div&gt;\n    &lt;p&gt;載入失敗：{error}&lt;/p&gt;\n    &lt;button onClick={reload}&gt;重試&lt;/button&gt;\n  &lt;/div&gt;\n);\n\nif (list.length === 0) return &lt;p&gt;目前沒有資料&lt;/p&gt;;\n\nreturn &lt;Table rows={list} /&gt;;</pre><b>順序很重要：</b>loading → error → empty → 正常資料，用 early return 一層層擋。" , opts: ["if (error)...; if (loading)...; if (list.length===0)...; return <Table />","if (list.length===0)...; if (loading)...; if (error)...; return <Table />","if (loading)...; if (error)...; if (list.length===0)...; return <Table />","所有狀態用三元運算子寫在同一個 return 內，不使用 early return"], ans: 2},
  { m:2,w:3,d:1,t:"程式題",q:"用 React Router 設定兩個頁面：/users 顯示 UserList、/users/:id 顯示 UserDetail。",a:"<pre>import { BrowserRouter, Routes, Route } from 'react-router-dom';\n\nfunction App() {\n  return (\n    &lt;BrowserRouter&gt;\n      &lt;Routes&gt;\n        &lt;Route path=\"/users\" element={&lt;UserList /&gt;} /&gt;\n        &lt;Route path=\"/users/:id\" element={&lt;UserDetail /&gt;} /&gt;\n      &lt;/Routes&gt;\n    &lt;/BrowserRouter&gt;\n  );\n}</pre><code>:id</code> 是動態參數，在 UserDetail 裡用 <code>useParams()</code> 取得。" , opts: ["在 Route 的 path 中用查詢字串 ?id=123 傳遞，用 useSearchParams 取得","動態參數透過 props.match.params 取得，需要用 withRouter 包裝元件","用 path='/users/:id' 定義動態路由，在 UserDetail 中用 useParams() 取得 id","動態參數必須透過 state 傳遞，在 navigate 時帶入 state 物件再用 useLocation 讀取"], ans: 2},
  { m:2,w:3,d:2,t:"觀念題",q:"useNavigate 和 useParams 各是做什麼的？列表頁點某一列跳到詳細頁，兩個怎麼配合？",a:"<ul><li><b>useNavigate</b>：用程式控制跳轉，<code>navigate('/users/' + row.id)</code></li><li><b>useParams</b>：在目標頁取得網址上的動態參數，<code>const { id } = useParams()</code></li></ul>流程：列表頁點擊 → navigate 帶 id 跳轉 → 詳細頁 useParams 拿到 id → useEffect 用 id 打單筆 API → 渲染。" , opts: ["useNavigate 取得網址動態參數；useParams 用程式觸發頁面跳轉","兩者功能相同，都用於頁面跳轉，差別只在語法","useNavigate 處理 query string；useParams 處理 hash 路由","useNavigate 用程式控制跳轉；useParams 取得網址上的動態參數"], ans: 3},
  { m:2,w:3,d:3,t:"程式題",q:"一個查詢表單有 keyword、status、startDate 三個欄位。請用「一個物件 state」管理它們，並寫出通用的 onChange 處理。",a:"<pre>const [query, setQuery] = useState({\n  keyword: '', status: 'all', startDate: '',\n});\n\nconst handleChange = (field, value) =&gt; {\n  setQuery(prev =&gt; ({ ...prev, [field]: value }));\n};\n\n// 使用\n&lt;input value={query.keyword}\n  onChange={e =&gt; handleChange('keyword', e.target.value)} /&gt;</pre>" , opts: ["為每個欄位分別建立獨立的 useState，onChange 各自對應獨立的 setter","用一個物件 state 集中管理所有欄位，透過通用 handleChange 以 spread 更新指定欄位","用 useReducer 管理所有欄位，每個欄位對應一個 dispatch action type","將所有欄位存在 ref 中，提交時再一次性讀取所有值"], ans: 1},
  { m:2,w:3,d:4,t:"觀念題",q:"表單送出時為什麼要呼叫 e.preventDefault()？不寫會發生什麼事？",a:"HTML form 的預設行為是<b>提交並重新載入整個頁面</b>。SPA 裡我們要自己用 JS 打 API，所以必須 <code>e.preventDefault()</code> 取消預設行為，否則頁面一閃重整、state 全部歸零、API 還沒打完就被中斷。<pre>const onSubmit = (e) =&gt; {\n  e.preventDefault();\n  search(query);\n};</pre>" , opts: ["防止 React 的合成事件冒泡到原生 DOM 事件處理器","阻止 HTML form 預設的提交並重新載入頁面行為，讓 SPA 能用 JS 打 API","避免表單中的 input 觸發不必要的重新渲染","確保所有欄位驗證完成後才送出，防止中途中斷"], ans: 1},
  { m:2,w:3,d:5,t:"程式題",q:"設計「新增 / 編輯共用一個 Modal」的 state：要能知道 Modal 開或關、目前是新增還是編輯、編輯的是哪一筆。",a:"<pre>const [modal, setModal] = useState({ open: false });\n\n// 開新增\nsetModal({ open: true, mode: 'create' });\n// 開編輯\nsetModal({ open: true, mode: 'edit', row });\n// 關閉\nsetModal({ open: false });</pre>用 union type 把「不可能的狀態」從型別上排除，比三個零散的 useState 不容易出 bug。" , opts: ["分別用 isOpen、isEdit、editRow 三個獨立 state 管理 Modal 的各種狀態","用一個 modal 物件 state，含 open、mode、row 欄位，統一管理開關、模式與資料列","用 useReducer 管理 Modal，定義 OPEN_CREATE、OPEN_EDIT、CLOSE 三個 action","Modal 的 open 狀態放在父元件，編輯資料透過 Context 傳入 Modal 元件"], ans: 1},
  { m:2,w:4,d:1,t:"觀念題",q:"一個後台查詢頁（查詢條件 + 表格 + 分頁 + 編輯 Modal）應該怎麼拆元件？每個元件的責任是什麼？",a:"<pre>UserPage（容器：擁有 query / list / modal 等 state，負責打 API）\n├── SearchForm（收集查詢條件，送出時呼叫 props.onSearch）\n├── UserTable（純顯示資料，點編輯時呼叫 props.onEdit(row)）\n├── Pagination（顯示頁碼，換頁呼叫 props.onPageChange）\n└── UserModal（表單本身，送出呼叫 props.onSubmit）</pre><b>原則：</b>state 與 API 集中在頁面層，子元件只透過 props 收資料、發事件。" , opts: ["所有邏輯和 UI 都寫在同一個元件，避免 props 傳遞的複雜度","依功能拆成盡可能多的小元件，每個元件都有自己的 state 和 API 呼叫","容器元件 UserPage 擁有 state 和 API 呼叫，SearchForm/UserTable/Pagination/UserModal 只透過 props 接收資料和事件","用 Context 把所有 state 放到最頂層，每個子元件直接從 Context 取用"], ans: 2},
  { m:2,w:4,d:2,t:"程式題",q:"設計分頁的 state 與換頁邏輯：page、pageSize、total，並算出總頁數。",a:"<pre>const [page, setPage] = useState(1);\nconst [pageSize] = useState(10);\nconst [total, setTotal] = useState(0);\n\nconst totalPages = Math.ceil(total / pageSize);\n\nuseEffect(() =&gt; {\n  fetchList({ page, pageSize, ...query }).then(res =&gt; {\n    setList(res.data.list);\n    setTotal(res.data.total);\n  });\n}, [page]);</pre>" , opts: ["totalPages = total - pageSize；useEffect 依賴 [pageSize]","totalPages = total * pageSize；直接在 onClick 中呼叫 fetch","totalPages = Math.floor(total / pageSize)；useEffect 依賴 [page]","totalPages = Math.ceil(total / pageSize)；useEffect 依賴 [page]"], ans: 3},
  { m:2,w:4,d:3,t:"觀念題",q:"查詢頁的「清除」按鈕按下去，應該發生哪些事？常見的遺漏是什麼？",a:"<b>完整行為：</b><ol style='margin-left:22px'><li>查詢條件 state 重設回初始值</li><li>page 重設回第 1 頁</li><li>用初始條件<b>重新查詢一次</b></li></ol><b>常見遺漏：</b>只清了 input 畫面，但實際送出的 query state 沒清；或忘記重設 page，導致空條件查詢卻停在第 5 頁看到空白。" , opts: ["只需清空 input 的顯示值，query state 保留不動以免觸發多餘的 API 呼叫","重設條件 state 與 input 顯示值即可，分頁通常不需要重設","條件 state 重設初始值、page 重設回第 1 頁、並用初始條件重新查詢；常見遺漏是只清畫面沒清 state 或忘記重設 page","直接重新整理整個頁面，確保所有狀態都回到初始值"], ans: 2},
  { m:2,w:4,d:4,t:"觀念題",q:"useMemo 和 useCallback 各解決什麼問題？什麼時候「不需要」用？",a:"<ul><li><b>useMemo</b>：快取「計算結果」，依賴沒變就不重算。用於昂貴計算（大量資料 filter / sort）</li><li><b>useCallback</b>：快取「函式參考」，依賴沒變函式就是同一個。用於把函式傳給被 React.memo 包住的子元件</li></ul><b>不需要用：</b>計算很便宜、子元件沒有 memo 化時，加了只是徒增複雜度。" , opts: ["useMemo 快取函式參考；useCallback 快取計算結果；任何時候都應該使用以提升效能","useMemo 快取計算結果；useCallback 快取函式參考；計算簡單或子元件未 memo 化時不需要用","兩者功能相同，都是用來避免子元件重新渲染，應該盡量使用","useMemo 只用在非同步操作；useCallback 只用在事件處理函式"], ans: 1},
  { m:2,w:4,d:5,t:"任務題",q:"【本週任務】完成 React 後台查詢頁 Demo。",a:"<b>驗收清單（對照計畫第 2 個月產出）：</b><ul><li>☐ 查詢條件 + 查詢按鈕 + 清除按鈕</li><li>☐ 表格列表（MUI DataGrid 或一般 table）</li><li>☐ 分頁功能</li><li>☐ 新增按鈕 + 編輯 Modal</li><li>☐ loading / error / empty 三狀態</li><li>☐ 元件至少拆成 SearchForm / Table / Modal</li><li>☐ 能口頭說明每個 component 的責任</li></ul>" , opts: ["只需完成表格列表與分頁功能，其他功能為加分項目","完成查詢條件與送出即可，Modal 和三狀態處理屬於進階需求","查詢條件+清除、表格、分頁、新增/編輯 Modal、loading/error/empty 三狀態、元件拆分為 SearchForm/Table/Modal","完成查詢條件、表格與 loading 狀態，分頁與 Modal 可留待下週實作"], ans: 2},

  /* ====== 第 3 個月：API 與資料流 ====== */
  { m:3,w:1,d:1,t:"觀念題",q:"RESTful API 中 GET / POST / PUT / DELETE 分別對應 CRUD 的哪個動作？以 /users 資源各舉一例。",a:"<ul><li><b>GET /users</b> → Read 列表；<b>GET /users/1</b> → Read 單筆</li><li><b>POST /users</b> → Create 新增（資料放 body）</li><li><b>PUT /users/1</b> → Update 更新整筆（PATCH 為部分更新）</li><li><b>DELETE /users/1</b> → Delete 刪除</li></ul>規律：<b>網址描述資源、動詞描述操作</b>。" , opts: ["GET→Read、POST→Create、PUT→Update、DELETE→Delete，動詞描述操作資源","GET→Create、POST→Read、PUT→Delete、DELETE→Update","GET 和 POST 都能 Read，PUT 和 DELETE 只用於管理員操作","GET→Read、POST→Update、PUT→Create、DELETE→Delete"], ans: 0},
  { m:3,w:1,d:2,t:"觀念題",q:"query params 和 request body 有什麼差別？查詢條件和新增表單的資料分別該放哪裡？",a:"<ul><li><b>query params</b>：接在網址後 <code>?keyword=amy&page=1</code>，用於 GET 的<b>查詢 / 篩選 / 分頁</b>條件</li><li><b>request body</b>：放在請求本體，用於 POST / PUT 要<b>建立或修改的資料</b></li></ul>所以：查詢條件 → query params；新增表單 → body。" , opts: ["兩者都可以互換使用，差別只在於資料大小限制","query params 放在網址後用於 GET 查詢篩選，request body 放請求本體用於 POST/PUT 建立修改","query params 用於 POST 新增表單，request body 用於 GET 查詢條件","查詢條件和新增表單都應放在 request body，query params 僅用於版本號"], ans: 1},
  { m:3,w:1,d:3,t:"觀念題",q:"HTTP 狀態碼 200、400、401、403、404、500 各代表什麼？前端各該怎麼反應？",a:"<ul><li><b>200</b> 成功 → 正常渲染</li><li><b>400</b> 請求參數錯誤 → 顯示後端錯誤訊息</li><li><b>401</b> 未登入 / token 過期 → 導回登入頁</li><li><b>403</b> 沒有權限 → 顯示無權限提示</li><li><b>404</b> 資源不存在 → 顯示查無資料</li><li><b>500</b> 伺服器錯誤 → 顯示通用錯誤、提供重試</li></ul>" , opts: ["200 成功、400 未登入、401 請求錯誤、403 資源不存在、404 無權限、500 伺服器錯誤","200 成功、400 請求參數錯誤、401 未登入或 token 過期、403 無權限、404 資源不存在、500 伺服器錯誤","200 成功、400 伺服器錯誤、401 無權限、403 未登入、404 請求參數錯誤、500 資源不存在","200 成功、400 無權限、401 資源不存在、403 請求錯誤、404 未登入、500 伺服器錯誤"], ans: 1},
  { m:3,w:1,d:4,t:"觀念題",q:"為什麼不建議在 component 裡直接寫 fetch，而要拆出一層 API service？",a:"<b>API service 分層的好處：</b><ul><li>共用邏輯集中：baseURL、token header、錯誤處理、response 解包只寫一次</li><li>元件變乾淨：元件只關心「呼叫 getUsers() 拿到資料」，不關心 HTTP 細節</li><li>好替換好測試：換 Mock API、換 axios、寫測試都只動 service 層</li></ul>" , opts: ["直接在 component 寫 fetch 更直覺，閱讀性最好，不需要額外拆層","拆出 API service 只是為了讓程式碼看起來更整齊，沒有實質好處","共用邏輯集中一處、元件只關心呼叫、易替換易測試，避免重複撰寫 token 與錯誤處理","拆出 service 層是為了讓 API 呼叫可以在瀏覽器快取，提升效能"], ans: 2},
  { m:3,w:1,d:5,t:"程式題",q:"用文字寫出一條完整資料流：使用者在查詢頁按下「查詢」按鈕後，到資料出現在表格上，中間經過哪些步驟？",a:"<pre>1. 按鈕 onClick 觸發 handleSearch\n2. handleSearch 整理 query state → 呼叫 api/user.ts 的 getUsers(params)\n3. service 組出 GET /api/users?keyword=...&page=1 發出請求\n4. 後端回傳 response JSON { code, data: { list, total } }\n5. service 檢查狀態、解包出 data\n6. 頁面 setList(data.list)、setTotal(data.total)\n7. state 改變 → React 重新渲染 → Table 收到新 props → 畫面更新</pre>" , opts: ["onClick → setList 清空 → fetch → 後端回應 → 畫面重渲染 → Table 更新","handleSearch 整理 query → onClick 觸發 → 後端直接更新 Table → setList 儲存結果","onClick → handleSearch 整理 query → service 組 GET URL → 後端回 response → setList/setTotal → React 重渲染 → Table 顯示新資料","onClick → service 直接發請求 → 後端回應 → component 自動偵測並重渲染，無需 setState"], ans: 2},
  { m:3,w:2,d:1,t:"觀念題",q:"分頁 API 的參數通常怎麼設計？前端送什麼、後端回什麼？換 pageSize 時前端要注意什麼？",a:"<b>前端送：</b><code>page</code>、<code>pageSize</code>（也有用 offset / limit 的）。<b>後端回：</b><code>list</code> 當頁資料 + <code>total</code> 總筆數。<b>注意：</b>pageSize 改變時要把 page 重設回 1；串接前先和後端確認 page 從 0 還是 1 開始。" , opts: ["前端送 offset、limit；後端回 list、total；換 pageSize 時不需重設頁碼","前端送 page、pageSize；後端回 list、total；換 pageSize 時需將 page 重設回 1","前端送 page、pageSize；後端只回 list，total 由前端自行計算陣列長度","前端只送 page；pageSize 由後端固定決定"], ans: 1},
  { m:3,w:2,d:2,t:"程式題",q:"寫一支查詢 API service：getUsers({ keyword, page, pageSize })，把參數轉成 query string 發出 GET。",a:"<pre>export async function getUsers(q) {\n  const params = new URLSearchParams();\n  if (q.keyword) params.set('keyword', q.keyword);\n  params.set('page', String(q.page));\n  params.set('pageSize', String(q.pageSize));\n\n  const res = await fetch('/api/users?' + params.toString());\n  if (!res.ok) throw new Error('HTTP ' + res.status);\n  return res.json();\n}</pre>用 <code>URLSearchParams</code> 組字串可自動處理編碼。" , opts: ["直接用字串拼接：fetch('/api/users?keyword=' + q.keyword + '&page=' + q.page)","把參數放進 request body 用 POST 發出，避免 URL 過長","用 JSON.stringify 把參數轉成字串後附加到網址上","用 URLSearchParams 組字串，逐一 set 後用 toString() 附加到 URL"], ans: 3},
  { m:3,w:2,d:3,t:"觀念題",q:"使用者輸入關鍵字查詢後翻到第 3 頁，再按「下一頁」。要怎麼確保查詢條件不會掉？常見的 bug 寫法是什麼？",a:"<b>正確設計：</b>查詢條件存在 state，<b>每次</b>呼叫列表 API 都帶上「目前條件 + 目前頁碼」。<b>常見 bug：</b>查詢按鈕用的是表單值、換頁卻只送 page 不帶條件，於是翻頁後條件消失、列表變回全部資料。" , opts: ["翻頁時重新打開查詢表單讓使用者再輸入一次條件","每次呼叫列表 API 都帶上目前條件加目前頁碼；常見 bug 是換頁只送 page 不帶查詢條件","把查詢條件存在 localStorage，翻頁時從 localStorage 讀取即可","條件直接存在網址 hash 中，換頁時瀏覽器會自動帶上所有參數"], ans: 1},
  { m:3,w:2,d:4,t:"程式題",q:"詳細頁需要打 GET /api/users/:id。寫出 service 與頁面端取得 id 並載入的程式。",a:"<pre>// api/user.ts\nexport async function getUser(id) {\n  const res = await fetch('/api/users/' + id);\n  if (!res.ok) throw new Error('HTTP ' + res.status);\n  return res.json();\n}\n\n// 頁面元件\nconst { id } = useParams();\nuseEffect(() =&gt; {\n  if (!id) return;\n  getUser(id).then(res =&gt; setUser(res.data));\n}, [id]);</pre>" , opts: ["用 useSearchParams 取得 id，在 onClick 事件中呼叫 getUser","直接從 props 取得 id，在 render 函式內直接呼叫 getUser","用 useParams 取得 id，在 useEffect 中判斷 id 存在才呼叫 getUser 並用 setUser 儲存","用 useContext 從全域取得 id，搭配 useMemo 在資料變動時自動重新載入"], ans: 2},
  { m:3,w:2,d:5,t:"程式題",q:"用 TanStack Query 的 useQuery 改寫「載入使用者列表」，並說出它比手寫 useEffect 多了哪些好處。",a:"<pre>const { data, isLoading, isError, refetch } = useQuery({\n  queryKey: ['users', query, page],\n  queryFn: () =&gt; getUsers({ ...query, page, pageSize }),\n});</pre><b>好處：</b>loading / error 狀態內建、queryKey 變了自動重新請求、內建快取、refetch 一行實現「重試」按鈕。" , opts: ["useQuery 與手寫 useEffect 功能完全相同，差別只在語法較簡潔","useQuery 內建 loading/error 狀態、queryKey 變動自動重請求、快取、一行實現 refetch 重試","useQuery 最大優點是不需要設定 queryKey，會自動偵測資料變化","useQuery 主要好處是可以直接操作 DOM，不需要透過 React 的 state 機制"], ans: 1},
  { m:3,w:3,d:1,t:"觀念題",q:"「新增資料」的完整前端流程是什麼？從打開 Modal 到列表更新，列出每一步。",a:"<pre>1. 點「新增」→ 打開 Modal（表單為初始值）\n2. 使用者填寫 → 前端驗證（必填、格式）\n3. 通過 → POST /api/users，body 帶表單資料，按鈕進入 loading\n4. 成功 → 關閉 Modal、顯示成功提示、重新呼叫列表 API\n5. 失敗 → Modal 保持開啟、顯示後端錯誤訊息</pre>" , opts: ["填寫 → 開 Modal → POST API → 關 Modal → 重查列表 → 顯示提示訊息","開 Modal → 填寫 → POST API → 前端驗證 → 成功關 Modal，失敗顯示錯誤","開 Modal（初始值）→ 填寫 → 前端驗證 → POST API（loading）→ 成功關 Modal 提示重查列表，失敗保持開啟顯示錯誤","開 Modal → 填寫 → POST API → 成功直接更新 state 新增一筆，不需重查列表"], ans: 2},
  { m:3,w:3,d:2,t:"觀念題",q:"編輯 Modal 要顯示既有資料，有兩種做法：直接用列表那一列的資料、或開 Modal 時打單筆 API。各適合什麼情況？",a:"<ul><li><b>用列表資料</b>：簡單、零延遲。適合列表欄位已包含全部編輯欄位時。注意要<b>複製一份</b>進表單 state</li><li><b>打單筆 API</b>：適合詳細資料欄位比列表多、或資料常被他人異動需要最新值</li></ul>實務上中大型後台常用第二種，確保編輯的是最新資料。" , opts: ["永遠都應該打單筆 API，確保資料是最新的，用列表資料風險太高","用列表資料適合欄位已包含全部編輯欄位；打單筆 API 適合詳細欄位較多或需要最新值","兩種做法效果完全相同，選哪個取決於工程師個人偏好","列表資料用於唯讀顯示，編輯 Modal 一律都必須打單筆 API 才正確"], ans: 1},
  { m:3,w:3,d:3,t:"觀念題",q:"刪除功能要注意什麼？「樂觀更新（optimistic update）」是什麼意思？",a:"<b>刪除的基本款：</b>一定要有確認對話框 → DELETE API → 成功後重查列表或從 state 移除該筆 → 失敗顯示錯誤。<b>樂觀更新：</b>不等 API 回來，先把畫面改掉，API 失敗再還原並提示。" , opts: ["刪除不需確認對話框，直接呼叫 DELETE API 效率最高","樂觀更新是指：等 API 回應成功後才更新畫面，確保資料正確性","基本做法是確認後呼叫 DELETE 再重查；樂觀更新是先改畫面，API 失敗再還原並提示","刪除後只需在前端移除該筆資料，不需要重查列表以節省請求次數"], ans: 2},
  { m:3,w:3,d:4,t:"程式題",q:"每支 API 失敗都要顯示錯誤訊息、401 要導回登入頁。怎麼避免在每個呼叫處重複寫這些邏輯？",a:"在 service 層做一個<b>統一的 request 包裝</b>：<pre>async function request(url, options) {\n  const res = await fetch(url, options);\n  if (res.status === 401) {\n    location.href = '/login';\n    throw new Error('未登入');\n  }\n  const json = await res.json();\n  if (!res.ok || json.code !== 0) {\n    throw new Error(json.message || 'HTTP ' + res.status);\n  }\n  return json.data;\n}</pre>" , opts: ["在每個元件的 catch 區塊分別處理 401 跳轉，確保各頁面行為一致","用 React Context 在全域監聽所有 API 錯誤，統一顯示 Toast 通知","在 service 層建立統一的 request 包裝函式，集中處理 401 跳轉、錯誤解包與訊息 throw","使用 try/catch 包住每次 fetch 呼叫，並在每個頁面元件頂層加上錯誤邊界"], ans: 2},
  { m:3,w:3,d:5,t:"程式題",q:"表單送出前要驗證：name 必填、email 必填且格式正確。寫出驗證函式並回傳錯誤訊息物件。",a:"<pre>function validate(form) {\n  const errors = {};\n  if (!form.name.trim()) errors.name = '請輸入姓名';\n  if (!form.email.trim()) errors.email = '請輸入 Email';\n  else if (!/^\\S+@\\S+\\.\\S+$/.test(form.email)) errors.email = 'Email 格式不正確';\n  return errors;\n}\n\nconst errors = validate(form);\nif (Object.keys(errors).length > 0) { setErrors(errors); return; }</pre>" , opts: ["驗證函式回傳布林值 true/false；用 if (!isValid) return 阻止送出","驗證函式回傳 errors 物件 { name?, email? }；若有錯誤則 setErrors 並 return 阻止送出","驗證直接在 JSX 的 input onChange 裡處理，不需要獨立的驗證函式","使用 HTML5 的 required 屬性即可，不需要在 JavaScript 層撰寫驗證邏輯"], ans: 1},
  { m:3,w:4,d:1,t:"觀念題",q:"畫面上有個欄位顯示的數字怪怪的。寫出你用 DevTools「從畫面反查到 API」的標準步驟。",a:"<pre>1. 確認現象：哪個欄位、什麼值、預期是什麼\n2. 開 Network 面板 → 重新觸發查詢\n3. 找到對應的 API 請求\n4. 看 Response：後端給的原始值對不對？\n   ├─ Response 就是錯的 → 看 Payload，確認前端送的參數\n   └─ Response 是對的 → 問題在前端 mapping 或顯示邏輯\n5. 記下結論：問題在「送出參數 / 後端資料 / 前端轉換」哪一段</pre>" , opts: ["先檢查 Console 錯誤 → 看 Elements 面板 → 對照設計稿 → 再去看 Network 請求","直接在程式碼加 console.log 印出所有變數，逐一比對直到找到問題","確認現象 → Network 找對應請求 → 先看 response 是否正確（二分法）→ 再查 payload 或前端 mapping","先假設是後端問題，請後端確認 API 回傳值，前端不需要自行排查"], ans: 2},
  { m:3,w:4,d:2,t:"觀念題",q:"在 Chrome DevTools 的 Network 面板裡，一個請求的「送出參數」和「回傳資料」分別在哪裡看？還有哪些常用資訊？",a:"<ul><li><b>Payload</b>：GET 的 Query String Parameters、POST 的 Request Payload——這就是前端實際送出的東西</li><li><b>Response / Preview</b>：後端回傳的原始 JSON</li><li><b>Headers</b>：請求方法、狀態碼、token 等 header</li><li><b>Timing</b>：請求耗時，慢的 API 在這裡現形</li></ul>" , opts: ["送出參數在 Headers tab 看，回傳資料在 Console tab 看","送出參數和回傳資料都在 Response tab，切換上下區塊即可","送出參數在 Preview tab 看，回傳資料在 Payload tab 看","送出參數在 Payload tab 看，回傳資料在 Response 或 Preview tab 看"], ans: 3},
  { m:3,w:4,d:3,t:"觀念題",q:"API 回傳的某欄位是 null 或缺失，畫面上有哪些處理選項？以「最後登入時間」為例說明怎麼選。",a:"<b>選項：</b><ol style='margin-left:22px'><li>顯示替代文字：「從未登入」「—」（最常用）</li><li>隱藏該欄位</li><li>顯示預設值 0 / 空陣列</li></ol><b>原則：</b>不能讓使用者看到 <code>null</code>、<code>undefined</code>、<code>NaN</code>、<code>Invalid Date</code> 字樣。" , opts: ["直接顯示 null 或 undefined，讓使用者知道欄位沒有資料","遇到 null 欄位應拋出錯誤，強制後端補齊資料後才顯示畫面","顯示替代文字如「從未登入」或「—」；絕不讓使用者看到 null、undefined、NaN、Invalid Date","用 JSON.stringify 轉成字串後顯示，這樣任何值都能安全顯示在畫面上"], ans: 2},
  { m:3,w:4,d:4,t:"程式題",q:"後端回傳 snake_case：{ user_name, created_at, is_active }，前端慣用 camelCase。寫一個 mapping 函式轉換，並說明為什麼建議在 service 層做。",a:"<pre>function toUser(dto) {\n  return {\n    userName: dto.user_name,\n    createdAt: dto.created_at,\n    isActive: dto.is_active,\n  };\n}</pre><b>在 service 層做的理由：</b>轉換只發生一次；後端改欄位名時只改 mapping 一處。" , opts: ["直接在 component 裡用解構取值：const { user_name, created_at } = apiData","在 API 呼叫後用 Object.keys 自動把所有 snake_case 轉成 camelCase","在 component 的 render 裡用三元運算子判斷欄位名稱後再顯示","在 service 層寫 toUser mapping 函式轉換欄位名；好處是轉換只發生一次、後端改名只需改一處"], ans: 3},
  { m:3,w:4,d:5,t:"任務題",q:"【本週任務】完成完整 CRUD 後台 Demo + API 追蹤筆記。",a:"<b>驗收清單：</b><ul><li>☐ 列表查詢 + 分頁 + 查詢條件保存</li><li>☐ 新增 / 編輯 / 刪除完整流程</li><li>☐ 表單驗證</li><li>☐ API loading / error 處理、統一 request 包裝</li><li>☐ 資料 mapping 在 service 層</li><li>☐ README：功能列表、資料夾結構、Mock API 說明</li><li>☐ 一份 API 追蹤筆記：每個畫面欄位 ↔ 哪支 API 哪個欄位的對照表</li></ul>" , opts: ["頁面 UI 美觀、動畫流暢、RWD 在手機上也能正常顯示","只要 CRUD 四個 API 都能呼叫成功，畫面上有顯示資料即可","列表查詢+分頁+條件保存、完整 CRUD 流程、表單驗證、統一 request 包裝、service 層 mapping、API 追蹤對照表","後端 API 文件齊全、Postman 測試全部通過、資料庫 schema 設計正確"], ans: 2},

  /* ====== 第 4 個月：工作案例 ====== */
  { m:4,w:1,d:1,t:"任務題",q:"用案例模板的前三段（背景 / 問題 / 追查），寫下你處理過的一個前端畫面或表格 Bug。還想不起來的話，先列出三個候選事件。",a:"<b>示範格式：</b><br><b>背景：</b>內部訂單管理系統的訂單列表頁。<br><b>問題：</b>切換到第 2 頁後用狀態篩選器查詢，表格顯示「查無資料」，但資料其實存在。<br><b>追查：</b>從篩選器的 onChange → 查詢 function → Network 看到 request 同時帶了 status=shipped 和 page=2 → 發現篩選後沒有重設頁碼。<br><br><b>檢查點：</b>背景一句講清楚「系統 + 畫面 + 誰在用」；追查要有具體路徑（事件 → function → API → 參數）。" , opts: ["系統名稱、具體畫面或功能、使用者角色，讓聽者明白哪個系統的哪個頁面出了什麼問題","只需說明出錯的技術原因與修復方式，不需要帶入使用者角色","列出所有可能原因並逐一排除，讓面試官了解你的分析過程","簡單說明時間點與負責人即可，背景不需要太多細節"], ans: 0},
  { m:4,w:1,d:2,t:"觀念題",q:"案例的「追查」段落是面試官最在意的部分。一段好的追查描述應該包含哪些元素？",a:"<b>四個元素：</b><ul><li><b>起點</b>：我從哪裡開始看（畫面現象 / 觸發事件）</li><li><b>路徑</b>：畫面 → 事件 → 前端 function → API request → response → 資料來源</li><li><b>排除法</b>：我怎麼確認問題「不在」某一層</li><li><b>工具</b>：用了什麼（Network 面板、斷點、console）</li></ul>面試官想聽的是<b>你的思考順序</b>，不是結論。" , opts: ["直接說明最終結論，不需要描述過程，面試官只在意你找到問題了沒","起點、路徑（事件→function→API→response）、排除法、工具","工具、時間、人員分工、最終解法","現象、原因、修正、驗證"], ans: 1},
  { m:4,w:1,d:3,t:"任務題",q:"把這句話改寫成有過程、有結果的案例語言：「我修了一個表格顯示錯誤的 bug。」",a:"<b>改寫示範：</b>「訂單列表在<b>篩選後沒有重設頁碼</b>，導致使用者誤以為查無資料。我從篩選事件追到查詢參數，發現 page 沒有歸 1，<b>修正後並補上『條件變更即重設頁碼』的共用邏輯</b>，同類問題在其他三個列表頁也一併解決。」<br><b>公式：</b>現象 → 原因 → 修正 → 擴散價值。" , opts: ["只要說明修正方式即可，不需要描述現象與擴散價值","先說原因，再說現象，最後補充修正，不需要提擴散價值","現象 → 原因 → 修正 → 擴散價值，並說明套用至其他頁面的範圍","現象 → 工具 → 測試結果 → 部署上線"], ans: 2},
  { m:4,w:1,d:4,t:"任務題",q:"為你 W1 的 Bug 案例補上「驗證」段：列出至少 3 個你會測的情境，涵蓋正常、邊界、回歸。",a:"<b>以「篩選未重設頁碼」為例：</b><ul><li><b>正常</b>：第 1 頁直接篩選，結果正確</li><li><b>重現路徑</b>：翻到第 2 頁再篩選，確認已修復</li><li><b>邊界</b>：篩選結果剛好 0 筆 / 剛好 1 頁滿 / 超過 1 頁</li><li><b>回歸</b>：清除按鈕、換 pageSize、重新整理後行為仍正常</li></ul>" , opts: ["只需驗證正常情境，異常情境留給 QA 負責","只要重現原本的 bug 路徑並確認修復即可","正常情境、重現路徑（原 bug 步驟確認已修復）、邊界與回歸","邊界測試、效能測試、安全性測試"], ans: 2},
  { m:4,w:1,d:5,t:"觀念題",q:"案例最後的「影響」段怎麼寫才有說服力？有哪些可以量化或具體化的角度？",a:"<b>可用的角度：</b><ul><li><b>使用者面</b>：影響哪些角色、多少人、什麼頻率的操作</li><li><b>範圍面</b>：同樣修正套用到幾個頁面 / 模組</li><li><b>時間面</b>：減少了多少重工、查錯時間</li><li><b>流程面</b>：因此建立了什麼慣例</li></ul>「每天」「三個列表頁」這類<b>具體詞</b>比「提升了系統穩定性」有力。" , opts: ["只要說「修好了」或「上線了」就夠，影響段不需要量化","影響段只需說明受影響的使用者數量，其他面向不重要","使用者面、範圍面、時間面（減少重工）、流程面（建立慣例）","影響段應聚焦技術細節，說明修改了哪些程式碼"], ans: 2},
  { m:4,w:2,d:1,t:"任務題",q:"用完整模板寫一個「畫面欄位與資料不一致」的 API / 資料流追蹤案例（背景到影響七段都要有）。",a:"<b>各段自我檢查：</b><ul><li>背景：系統 + 畫面 + 欄位名稱</li><li>問題：畫面顯示 X，但實際應該是 Y（兩個值都寫出來）</li><li>追查：有沒有寫出「我先看 response 對不對」的二分過程</li><li>原因：落點明確——送錯參數、後端資料、還是前端 mapping？</li><li>修正：具體改了哪個檔案 / 哪段邏輯</li><li>驗證：用哪幾筆資料、哪些情境比對</li><li>影響：這個欄位對使用者的決策有多重要</li></ul>" , opts: ["原因段只要說「後端資料有問題」就夠，不需要自己驗證","落點要明確（送錯參數、後端問題或前端 mapping 錯誤）且必須是驗證過的，非猜測","原因段可以列出所有可能性，讓面試官自行判斷哪個最合理","先說修正方式再回推原因，這樣更有說服力"], ans: 1},
  { m:4,w:2,d:2,t:"任務題",q:"為你負責的一個頁面建立「API 對照表」。這張表應該有哪些欄位？",a:"<b>建議欄位：</b><pre>| 畫面欄位 | API           | response 路徑     | 型別   | 空值處理 |\n|----------|---------------|-------------------|--------|-----------|\n| 訂單編號 | GET /orders   | data.list[].no    | string | 不會為空  |\n| 出貨時間 | GET /orders   | data.list[].ship_at| string|null | 顯示「—」 |</pre>" , opts: ["只需記錄 API 名稱與回傳格式，不需要追蹤到空值處理","畫面欄位、元件名稱、開發者姓名、更新日期","畫面欄位、API 名稱、response 路徑、型別、空值處理方式","API 名稱、HTTP method、狀態碼、錯誤訊息"], ans: 2},
  { m:4,w:2,d:3,t:"任務題",q:"用純文字（箭頭式）畫出你某個功能的資料流圖：從使用者操作到畫面更新。",a:"<b>格式示範：</b><pre>[使用者] 點擊「查詢」\n   ↓ onClick\n[SearchForm] 收集條件 → onSearch(query)\n   ↓\n[UserPage] handleSearch → setPage(1)\n   ↓\n[api/user.ts] getUsers({query, page})\n   ↓ GET /api/users?keyword=...\n[後端] 查 DB → 回 { list, total }\n   ↓\n[UserPage] setList / setTotal\n   ↓ re-render\n[UserTable] 顯示新資料</pre>" , opts: ["起點是 API response，終點是後端資料庫，不需要包含前端 re-render","起點是元件 mount，終點是 state 更新，中間包含 API 呼叫","起點與終點都是後端，前端只是中間的傳遞層","起點是使用者操作（如點擊查詢），終點是畫面顯示新資料，中間包含事件到 re-render 的完整鏈"], ans: 3},
  { m:4,w:2,d:4,t:"任務題",q:"發現某支 API 的 response 疑似有問題，要去問後端。用「問問題模板」寫出一則完整的訊息。",a:"<b>示範：</b><pre>【訂單列表 ship_at 欄位疑似異常】\n背景：訂單管理系統列表頁，串 GET /api/orders\n現象：訂單編號 A1234 的 ship_at 回傳 null\n預期：這筆訂單在後台已標記出貨，應有時間\n已查：前端送出參數正確（截圖）；Network response 中該欄位即為 null（截圖）\n判斷：懷疑是該筆資料寫入時未更新 ship_at\n想確認：DB 中這筆的 ship_at 實際值？</pre>" , opts: ["直接說「我覺得是後端問題」並請對方確認，省去截圖準備時間","只附上錯誤截圖即可，不需要說明自己查過什麼","必須先附上「已查」：確認前端參數正確（截圖）且 Network response 中該欄位即為問題值（截圖）","先問後端有沒有最近改過 API，再決定要不要附截圖"], ans: 2},
  { m:4,w:2,d:5,t:"觀念題",q:"案例中「現象」和「原因」常被混在一起寫。它們的差別是什麼？怎麼自我檢查有沒有寫混？",a:"<ul><li><b>現象</b>：觀察到的事實——「畫面顯示金額為 0」「第 2 頁篩選後查無資料」</li><li><b>原因</b>：經過追查確認的根因——「mapping 時把 amount 寫成 ammount 拿到 undefined」</li></ul><b>自我檢查法：</b>原因句必須能回答「<b>為什麼</b>會出現那個現象」，而且是你<b>驗證過</b>的。" , opts: ["現象和原因可以放在同一段，這樣更簡潔有效率","原因句必須能回答「為什麼會出現那個現象」且是驗證過的，不是推測","只要描述得夠詳細，現象和原因混在一起也沒關係","原因段只需說明你的修法，不需要解釋因果關係"], ans: 1},
  { m:4,w:3,d:1,t:"任務題",q:"寫一個「測試機正常、正式機出問題」（或相反）的案例。這類案例的「原因」通常落在哪幾類？",a:"<b>環境差異的常見根因：</b><ul><li>環境變數 / API base URL 設定不同</li><li>資料差異：測試機資料乾淨、正式機有歷史髒資料</li><li>版本差異：前後端部署版本不同步</li><li>快取：CDN、瀏覽器快取了舊版 bundle</li><li>權限 / 防火牆 / CORS 設定不同</li></ul>" , opts: ["通常是前端 code 有 bug，測試機沒觸發但正式機資料量大才觸發","幾乎一定是後端問題，前端環境不同不會造成這類差異","環境變數或 API URL 不同、資料差異、前後端版本不同步、CDN 快取、權限或 CORS 設定不同","大多是 CI/CD pipeline 設定錯誤，與環境變數無關"], ans: 2},
  { m:4,w:3,d:2,t:"任務題",q:"整理你參與過（或設想中）的災演 / 切換文件，它應該包含哪些章節？",a:"<b>災演文件基本結構：</b><ul><li><b>目的與範圍</b></li><li><b>前置檢查</b></li><li><b>操作步驟</b>（逐步，每步附預期結果）</li><li><b>驗證清單</b></li><li><b>回退程序</b></li><li><b>聯絡窗口與時程</b></li></ul>「整理災演操作文件，將切換步驟與驗證清單標準化，降低正式環境切換風險」——這正是計畫裡建議的履歷句之一。" , opts: ["只需記錄操作步驟，其他章節可省略以保持文件簡潔","目的與範圍、前置檢查、操作步驟（含預期結果）、驗證清單、回退程序、聯絡窗口與時程","操作步驟、聯絡窗口、截圖紀錄","問題描述、解法、上線日期"], ans: 1},
  { m:4,w:3,d:3,t:"任務題",q:"為你的系統（或 CRUD Demo）寫一份「上線前檢查清單」，至少 8 項。",a:"<b>參考清單：</b><ul><li>☐ API base URL 指向正式環境</li><li>☐ console.log / debug 程式碼已移除</li><li>☐ 環境變數已確認</li><li>☐ 主要流程手動跑過：查詢、新增、編輯、刪除</li><li>☐ 空資料、錯誤狀態畫面正常</li><li>☐ 權限角色各登入測一輪</li><li>☐ build 產物在正式機可正常載入</li><li>☐ 回退方案確認</li><li>☐ 通知相關人員上線時間</li></ul>" , opts: ["只要確認 build 成功就可以上線，其餘檢查項目可以事後補","主要檢查 UI 樣式是否正確，功能流程由 QA 負責","API base URL 指向正式環境、環境變數確認、主要 CRUD 手動跑過、empty 與 error 狀態正常、確認回退方案","只需確認測試機通過所有測試，正式機不需要額外驗證"], ans: 2},
  { m:4,w:3,d:4,t:"任務題",q:"設計一份「異常處理流程」文件的骨架：當系統出現問題時，團隊照著走的標準流程。",a:"<b>骨架：</b><pre>1. 接收與確認（誰回報、現象、影響範圍）\n2. 初步分級（P1 全面停擺 / P2 主要功能異常 / P3 局部問題）\n3. 排查（前端 Console / Network、後端 log、環境變更）\n4. 處置（能修就修；不能 → 回退或關閉功能開關）\n5. 記錄與覆盤（時間軸、根因、修正、預防措施）</pre>" , opts: ["第一步應該是立刻開始排查技術原因，不要浪費時間在確認現象上","第一步是通知所有相關人員，讓大家都知道有問題再開始處理","第一步是找到 root cause，然後再回頭決定影響範圍","第一步是接收與確認（誰回報、現象、影響範圍），以便分級（P1/P2/P3）決定處置優先度"], ans: 3},
  { m:4,w:3,d:5,t:"任務題",q:"把你 W3 整理的文件工作，濃縮成一句可放進履歷的描述。寫三個版本再挑最好的。",a:"<b>好句子的結構：</b>動詞開頭 + 具體產出 + 帶來的效果。<br><b>範例：</b><ul><li>「整理正式機 / 測試機切換與災演操作文件，將步驟與驗證清單標準化，降低環境切換風險」</li><li>「建立上線前檢查清單與異常處理流程，減少部署後緊急修復次數」</li></ul><b>避免：</b>「負責文件整理」這種沒有產出與效果的寫法。" , opts: ["只列出工具名稱（如 Confluence、Notion），讓面試官知道你熟悉文件工具","用被動語態描述文件內容，如「文件已整理完畢」","動詞開頭 + 具體產出 + 帶來的效果，如「整理切換文件，標準化步驟，降低環境切換風險」","說明文件字數與頁數，以量化方式展現工作量"], ans: 2},
  { m:4,w:4,d:1,t:"任務題",q:"把你最強的一個案例濃縮成 2 句履歷描述：第一句講你做了什麼，第二句講追查能力或成果。",a:"<b>示範：</b><br>「維護訂單管理系統列表與查詢功能，修正分頁與篩選條件互動造成的資料顯示異常。」<br>「從 UI 事件追蹤至 API 參數與 response 結構定位根因，並將修正擴及其他三個列表頁。」<br><b>檢查點：</b>有具體的系統 / 功能名詞；動詞是「修正、追蹤、定位」這類有力的詞。" , opts: ["第一句講追查過程，第二句講系統背景與功能說明","兩句都聚焦在技術細節，讓面試官評估你的技術深度","第一句講你做了什麼（系統+功能+行為），第二句講追查能力或成果","第一句講影響範圍，第二句講修復方法與工具"], ans: 2},
  { m:4,w:4,d:2,t:"觀念題",q:"面試時要在 3–5 分鐘內講完一個案例。請設計你的時間配置與每段要講什麼。",a:"<b>建議配置（以 4 分鐘為例）：</b><ul><li><b>0:00–0:30 背景與問題</b>：系統、誰在用、出了什麼狀況</li><li><b>0:30–2:30 追查過程</b>（重頭戲）：起點 → 路徑 → 排除法 → 根因</li><li><b>2:30–3:15 修正與驗證</b></li><li><b>3:15–4:00 影響與學到的事</b></li></ul><b>練習法：</b>計時錄音講一次，聽回放檢查追查段有沒有佔到一半時間。" , opts: ["「背景」段應佔最多時間，讓面試官充分理解問題情境","「影響」段應佔最多時間，因為面試官最在乎你帶來的價值","「追查過程」應佔約一半時間，因為面試官想聽思考順序與排除法","「修正」段應佔最多時間，說明你如何解決問題"], ans: 2},
  { m:4,w:4,d:3,t:"觀念題",q:"面試官聽完你的案例後追問：「你怎麼確定根因就是那個，而不是別的？」要怎麼回答才站得住腳？",a:"<b>站得住腳的三層證據：</b><ol style='margin-left:22px'><li><b>重現</b>：照特定步驟操作，問題必然出現</li><li><b>機制</b>：能解釋從根因到現象的因果鏈</li><li><b>消失</b>：只改那一處，問題就不再重現；改回去，問題又出現</li></ol>回答模板：「我先找到穩定重現的步驟，接著驗證了因果機制，最後確認只修改該處問題就解除。」" , opts: ["只要有重現就夠了，不需要解釋機制與消失條件","重現、機制（能解釋從根因到現象的因果鏈）、消失（只改那一處問題就解除）","工具截圖、同事確認、版本紀錄","只要說「我試過很多可能性最後確定是這個」就有說服力"], ans: 1},
  { m:4,w:4,d:4,t:"任務題",q:"檢視你的三個案例：每一個的「影響」段，找出至少一個可以加上的具體量詞或範圍詞。",a:"<b>可加的詞類型：</b><ul><li>頻率：「每日使用」「每月結算時」</li><li>範圍：「三個列表頁」「全部後台模組共用」</li><li>對象：「營運與客服共約 N 人」</li><li>前後對比：「原需手動比對半小時 → 修正後即時正確」</li></ul>" , opts: ["只說「修好了」就夠，面試官不需要知道影響多少人","只提使用者數量，不需要加入頻率與範圍","用技術指標（如減少幾行 code）來量化影響力最有效","同時包含頻率、範圍、對象，如「每日使用的訂單列表，套用至三個列表頁，約 20 人受益」"], ans: 3},
  { m:4,w:4,d:5,t:"任務題",q:"【本月驗收】三個案例完整度總檢查。",a:"<b>對照計畫第 4 個月驗收標準：</b><ul><li>☐ 3 個案例齊備：1 個畫面 / 表格、1 個 API / 資料流、1 個環境 / 文件流程</li><li>☐ 每個案例七段俱全</li><li>☐ 每個案例能在 3–5 分鐘內口述（實際計時過）</li><li>☐ 追查段講得出「思考順序與排除過程」</li><li>☐ 每個案例有 2 句履歷版描述</li></ul>" , opts: ["3 個案例只要有背景與修正兩段即可，其他段落是加分項","能口述超過 10 分鐘代表內容豐富，不需要限制在 3–5 分鐘","3 個案例七段俱全、每個能在 3–5 分鐘口述（計時過）、追查段講得出思考順序、每個有 2 句履歷版描述","只要有書面文字版本就算完成，不需要實際口述練習"], ans: 2},

  /* ====== 第 5 個月：面試準備 ====== */
  { m:5,w:1,d:1,t:"觀念題",q:"【面試題】Promise 和 async / await 的差異是什麼？",a:"<b>參考回答：</b>「async/await 是 Promise 的<b>語法糖</b>，底層都是 Promise。差異在寫法：.then 用回呼串接；async/await 讓非同步程式長得像同步，搭配 try/catch 統一處理錯誤更直覺。實務上我預設用 async/await，但並行請求時會搭配 Promise.all，因為逐一 await 會變成序列執行。」<br><b>加分點：</b>主動講出 Promise.all 的並行差異。" , opts: ["async/await 是 Promise 的語法糖，讓非同步程式看起來像同步，並行請求要用 Promise.all","async/await 底層不使用 Promise，是完全獨立的非同步機制","並行請求應逐一 await，確保每個請求依序完成再進行下一個",".then 串接與 async/await 錯誤處理方式完全相同，可互換使用"], ans: 0},
  { m:5,w:1,d:2,t:"觀念題",q:"【面試題】map、filter、reduce 各適合什麼情境？請用實際工作例子回答。",a:"<b>參考回答：</b>「<b>map</b> 是一對一轉換——把 API 回傳的 snake_case 資料轉成畫面格式；<b>filter</b> 是篩選——表格前端篩出啟用中的帳號；<b>reduce</b> 是聚合成單一值——把訂單明細加總成總金額，或把陣列轉成以 id 為 key 的物件方便查找。三者都回傳新資料、不改原陣列，可以串接。」" , opts: ["map 一對一轉換、filter 篩選、reduce 聚合成單一值，三者都不改原資料且可串接","map 用於篩選元素、filter 用於轉換資料、reduce 用於排序陣列","filter 和 map 會修改原陣列，reduce 回傳新陣列","reduce 只能用來做數字加總，不適合轉換成 key-value 物件"], ans: 0},
  { m:5,w:1,d:3,t:"觀念題",q:"【面試題】深拷貝與淺拷貝的差異？實務上踩過什麼坑？",a:"<b>參考回答：</b>「淺拷貝只複製第一層，巢狀物件仍共用參考；深拷貝（structuredClone）整棵複製。我實際踩過的坑是<b>編輯 Modal</b>：把列表的 row 物件直接放進表單 state，使用者改了表單還沒按儲存，列表畫面就跟著變了。解法是帶入表單時複製一份。」" , opts: ["淺拷貝只複製第一層，巢狀物件仍共用參考，常見坑是編輯 Modal 帶入列表 row 直接污染原始資料","淺拷貝和深拷貝都只複製第一層，差異在於是否保留原型鏈","使用展開運算子 {...obj} 可以產生完整深拷貝","深拷貝與淺拷貝在 React 中沒有差異，因為 state 更新會自動重新建立物件"], ans: 0},
  { m:5,w:1,d:4,t:"觀念題",q:"【面試題】請說明 event loop 的基本概念。",a:"<b>參考回答：</b>「JS 是單執行緒，event loop 負責調度任務。同步程式先執行完；非同步完成的回呼依類型排隊：<b>微任務</b>（Promise.then）優先，每輪同步結束後先清空；<b>宏任務</b>（setTimeout、事件回呼）排在之後。所以 <code>setTimeout(fn, 0)</code> 一定晚於 Promise.then。」" , opts: ["微任務（Promise.then）優先於宏任務（setTimeout），setTimeout(fn,0) 一定晚於 Promise.then 執行","setTimeout(fn, 0) 會比 Promise.then 更早執行，因為它的延遲時間最短","JS 是多執行緒的，微任務與宏任務可以同時並行執行","宏任務和微任務優先順序相同，依照程式碼撰寫順序依序執行"], ans: 0},
  { m:5,w:1,d:5,t:"觀念題",q:"【面試題】什麼是閉包（closure）？舉一個你實際用到的例子。",a:"<b>參考回答：</b>「閉包是函式記得並能存取它定義時所在作用域的變數，即使在外層函式執行完之後。實際例子：debounce——內部函式持續記得外層的 timer 變數，每次輸入先清掉上一個計時器，達到停止輸入 300ms 才打 API。」<pre>function debounce(fn, delay) {\n  let timer;\n  return (...args) =&gt; {\n    clearTimeout(timer);\n    timer = setTimeout(() =&gt; fn(...args), delay);\n  };\n}</pre>" , opts: ["閉包讓函式記住定義時的作用域變數，例如 debounce 透過閉包持續持有 timer 實現停止輸入後才打 API","閉包是讓函式能夠存取全域變數的語法特性，與作用域無關","閉包會造成記憶體洩漏，實務上應盡量避免使用","debounce 不需要閉包，用全域變數儲存 timer 也能達到相同效果"], ans: 0},
  { m:5,w:2,d:1,t:"觀念題",q:"【面試題】useState 和 useEffect 怎麼使用？各自的常見注意事項？",a:"<b>參考回答：</b>「useState 管理元件狀態，setter 觸發重渲染；注意 state 不可變（物件 / 陣列要建新的）、連續更新用函式式 <code>setX(prev => ...)</code>。useEffect 處理副作用（API、訂閱、DOM 操作），依賴陣列決定執行時機，用 cleanup 收拾計時器與監聽。」" , opts: ["useState 物件要建新的不可直接修改；useEffect 依賴陣列要誠實填、有訂閱就要有 cleanup","useState 可以直接修改物件屬性再呼叫 setState，React 會自動偵測到變更","useEffect 的依賴陣列可以留空，React 會自動追蹤所有用到的變數","連續呼叫 setState 會立即觸發多次 render，應盡量避免連續更新"], ans: 0},
  { m:5,w:2,d:2,t:"觀念題",q:"【面試題】useEffect 有哪些常見錯誤？你怎麼避免？",a:"<b>三個最常見：</b><ul><li><b>無限迴圈</b>：漏依賴陣列、或依賴了每次渲染都是新參考的物件 / 函式 → 用 useMemo / useCallback 穩定參考</li><li><b>沒寫 cleanup</b>：計時器、事件監聽殘留 → 養成「有訂閱就有退訂」的習慣</li><li><b>race condition</b>：舊請求晚回來覆蓋新資料 → 用 AbortController 取消</li></ul>" , opts: ["常見錯誤：無限迴圈（漏依賴陣列）、未寫 cleanup 造成殘留、race condition 導致舊請求覆蓋新資料","useEffect 無限迴圈只會在完全沒有依賴陣列時發生，有填依賴就不會出現","cleanup 函式只有在使用 setInterval 時才必須撰寫，addEventListener 不需要","race condition 在 useEffect 中不會發生，因為 React 會自動取消前一次請求"], ans: 0},
  { m:5,w:2,d:3,t:"觀念題",q:"【面試題】什麼是 props drilling？有哪些解法？",a:"<b>參考回答：</b>「props drilling 是資料要從頂層傳到深層元件，中間每一層都被迫經手自己用不到的 props。解法：<ul><li><b>元件組合</b>（children / slot）：先試這個</li><li><b>Context</b>：跨層共享的全域性資料</li><li><b>狀態管理庫</b>（Zustand / Redux）：多頁面共享時</li></ul>但兩三層的傳遞是正常的，不需要為此上工具。」" , opts: ["props drilling 是資料逐層傳遞，解法依序為元件組合、Context、狀態管理庫，兩三層傳遞屬正常","props drilling 只要超過兩層就必須立即改用 Redux，否則難以維護","Context 是 props drilling 的最佳解，任何情況都應優先使用 Context 取代 props 傳遞","props drilling 是 React 設計缺陷，所有資料都應存放在全域狀態管理庫中"], ans: 0},
  { m:5,w:2,d:4,t:"觀念題",q:"【面試題】你怎麼決定何時拆分 component？拆分的依據是什麼？",a:"<b>參考回答：</b>「我的依據有三個：<b>職責</b>——一個元件能用一句話說清楚它負責什麼；<b>重用</b>——同樣的 UI 出現第二次就抽出來；<b>狀態邊界</b>——讓 state 住在最低的共同父層。反過來說，我不會為了拆而拆——過度拆分讓追蹤資料流變困難。」" , opts: ["依職責單一、重用性、狀態邊界三個依據決定是否拆分，不為了拆而拆","每個元件超過 50 行就應該強制拆分，以保持程式碼簡潔","只要 UI 畫面上看起來是獨立區塊，就應該各自抽成一個元件","拆分元件越細越好，這樣 React 的效能優化才能充分發揮"], ans: 0},
  { m:5,w:2,d:5,t:"觀念題",q:"【面試題】如何避免不必要的 render？表單狀態又該怎麼管理？",a:"<b>避免不必要 render：</b>「先確認真的有效能問題（React DevTools Profiler），再依序：把 state 下放到最小範圍、React.memo 包純展示元件、useMemo / useCallback 穩定 props 參考。」<b>表單狀態：</b>「欄位少用一個物件 state + 通用 handleChange；欄位多、驗證複雜用 react-hook-form。」" , opts: ["先用 Profiler 確認效能問題，再下放 state、使用 memo/useMemo/useCallback；表單欄位少用物件 state，複雜用 react-hook-form","所有元件都應包裹 React.memo，這樣就不需要擔心不必要的 render","表單每個欄位應各自使用獨立的 useState，避免物件 state 合併時出錯","useMemo 和 useCallback 應大量使用，因為它們不會有任何額外開銷"], ans: 0},
  { m:5,w:3,d:1,t:"觀念題",q:"【面試題】type 和 interface 的差異？你的團隊（或你自己）的使用慣例是什麼？",a:"<b>參考回答：</b>「功能重疊度很高，差異：interface 可同名合併；type 能表達 union、交集、條件型別。我的慣例：<b>物件結構用 interface，狀態與組合型別用 type</b>，重點是專案內一致。被追問時補一句：union type 只能用 type 定義，這是最常遇到的硬差異。」" , opts: ["最硬差異是 union type 只能用 type 定義；物件結構用 interface，狀態與組合型別用 type，專案內保持一致","interface 和 type 功能完全不同，interface 只能描述物件，type 只能描述基本型別","union type 可以用 interface 或 type 定義，兩者在此功能上完全等價","React 專案中應全部使用 type，interface 只適合在 Node.js 後端使用"], ans: 0},
  { m:5,w:3,d:2,t:"觀念題",q:"【面試題】union type 在實務上怎麼用？請舉兩個例子。",a:"<b>參考回答：</b><ul><li><b>狀態列舉</b>：<code>type Status = 'idle' | 'loading' | 'success' | 'error'</code>，搭配 switch 渲染</li><li><b>可辨識聯合</b>：Modal state <code>{ open: false } | { open: true; mode: 'edit'; row: User }</code>，從型別上排除「編輯卻沒資料」的不可能狀態</li></ul>" , opts: ["union type 可用於狀態列舉與可辨識聯合設計，從型別上排除不可能的狀態組合","union type 只適合用在字串常數列舉，不適合用於包含物件屬性的複雜狀態","可辨識聯合（discriminated union）需要搭配 class 才能正常運作","union type 會讓 TypeScript 型別推斷變慢，複雜專案應改用 enum 取代"], ans: 0},
  { m:5,w:3,d:3,t:"觀念題",q:"【面試題】請說明 generic 的基本概念，以及你在專案中怎麼用。",a:"<b>參考回答：</b>「generic 是<b>型別的參數化</b>，把會變動的型別抽成參數，讓一份定義服務多種型別且保持型別安全。我最常用在：<ul><li>API 共用外層：<code>ApiResponse&lt;T&gt;</code></li><li>共用請求函式：<code>request&lt;T&gt;(url): Promise&lt;T&gt;</code></li></ul>」" , opts: ["generic 將型別參數化，常用於 ApiResponse<T> 共用外層結構與 request<T> 共用請求函式","generic 只能用在函式上，不能用於 interface 或 type 的定義","使用 generic 會讓型別推斷失效，應改用 any 確保函式的通用性","ApiResponse 不適合使用 generic，每支 API 都應定義獨立的完整型別"], ans: 0},
  { m:5,w:3,d:4,t:"觀念題",q:"【面試題】API response 的型別你會怎麼設計？欄位可能為 null 怎麼處理？",a:"<b>參考回答：</b>「我會照後端 response 由內往外逐層定義 interface，共用外層用 generic。可能為空的欄位誠實標 <code>string | null</code>，逼自己在畫面層處理空值。另外我習慣把後端 DTO 與前端 model 分開，在 service 層做 mapping。」" , opts: ["照後端 response 逐層定義 interface，共用外層用 generic；可能為空的欄位誠實標 string | null","所有 API response 欄位都應標記為 string，再由前端自行轉型以提高靈活度","nullable 欄位應使用 undefined 而非 null，因為 TypeScript 對 null 的處理較複雜","API 型別只需定義最外層結構，巢狀資料用 any 型別即可減少維護成本"], ans: 0},
  { m:5,w:3,d:5,t:"觀念題",q:"【面試題】React props 的型別怎麼設計？事件、children、可選值各怎麼寫？",a:"<b>參考回答骨架：</b><pre>interface CardProps {\n  title: string;\n  count?: number;              // 可選 + 解構給預設值\n  onSelect: (id: number) =&gt; void; // 事件\n  children?: React.ReactNode;  // children 標準型別\n}</pre>補充：「props 是元件的對外合約，我會讓型別表達使用限制——例如狀態用 union 限定取值。」" , opts: ["事件用 () => void、children 用 React.ReactNode、可選值用 ? 並在解構時給預設值","children 的型別應標記為 string，避免傳入非預期的 JSX 元素","所有 props 都應設為必填，可選值容易造成 undefined 錯誤","事件 handler 的型別應使用 React.MouseEvent，不能直接用 () => void"], ans: 0},
  { m:5,w:4,d:1,t:"觀念題",q:"【面試題】如何從畫面追到 API？請完整描述你的流程。",a:"<b>回答：</b>「先確認現象發生在哪個欄位 / 操作 → 開 Network 找到對應請求 → 先看 <b>response 對不對</b>做二分：response 錯，檢查送出的 payload / query，參數對就找後端；response 對，問題在前端 mapping 與渲染邏輯，必要時下斷點。最後說清楚問題落在『參數、後端資料、前端轉換』哪一段。」<br><b>最後加：</b>「我也習慣整理畫面欄位與 API 的對照表。」" , opts: ["確認現象欄位 → Network 找請求 → 二分法看 response 是否正確 → 再往 payload 或前端 mapping 追查","debug 應從前端程式碼開始往 API 追，不需要先看 Network 的 response","遇到資料錯誤應先修改前端 mapping 邏輯，確認沒問題再去查後端","Network 面板只能看到請求是否成功，無法判斷資料正確性，不適合用於 debug"], ans: 0},
  { m:5,w:4,d:2,t:"觀念題",q:"【面試題】表格分頁和查詢條件你會怎麼處理？前後端怎麼配合？",a:"<b>參考回答：</b>「分頁用後端分頁：前端送 page / pageSize，後端回 list / total。設計上注意：<b>條件或 pageSize 變更時 page 重設為 1</b>；每次請求都帶完整條件 + 頁碼；條件同步到網址 query string 讓重整可還原。串接前先跟後端對齊 page 從 0 還是 1 開始。」" , opts: ["條件或 pageSize 變更時 page 重設為 1，每次請求帶完整條件與頁碼，並同步至網址 query string","換頁時只需送出 page 參數，查詢條件由後端從 session 記憶，不需每次重送","分頁與查詢條件應分開管理，各自獨立發出 API 請求再由前端合併結果","query string 會暴露查詢條件，分頁狀態應存在 localStorage 而非網址列"], ans: 0},
  { m:5,w:4,d:3,t:"觀念題",q:"【面試題】如何 debug 線上（正式環境）問題？和開發環境有什麼不同？",a:"<b>參考回答：</b>「線上不能隨意改 code，流程是：先確認影響範圍與重現步驟 → 看 Console 與 Network 蒐集證據 → 比對最近的部署與設定變更 → 檢查環境差異 → 嚴重時先止血（回退版本）→ 事後在開發環境重現並補防護。」<b>關鍵詞：</b>「先止血再根治」「環境差異清單」。" , opts: ["先確認影響範圍與重現步驟，蒐集證據後比對最近部署，嚴重時先回退版本，事後補防護","線上問題應先找出根本原因再修復，止血措施可能掩蓋真正的問題","debug 線上問題應直接在正式環境加入 console.log 輸出，找到問題後再移除","遇到線上問題應立即重新部署最新程式碼，通常能解決大多數問題"], ans: 0},
  { m:5,w:4,d:4,t:"觀念題",q:"【面試題】改完一個功能，如何確認沒有影響到其他功能？",a:"<b>參考回答：</b>「三層確認：<b>影響面分析</b>——搜尋被改的函式 / 元件被誰引用，列出受影響清單；<b>測試</b>——跑原 bug 的重現路徑 + 相鄰功能回歸；<b>小步發布</b>——commit 拆小、PR 說明寫清楚改動範圍。共用元件的修改我會特別保守。」" , opts: ["三層確認：分析引用影響面、測試原路徑與相鄰功能回歸、將 commit 拆小並清楚說明 PR","改完功能只需確認原本的需求沒有問題，其他功能不在本次責任範圍內","透過全域搜尋找出所有引用後，只需重新跑一次主功能的測試即可","PR 越大越好，一次涵蓋多個功能才能確保整合測試的完整性"], ans: 0},
  { m:5,w:4,d:5,t:"任務題",q:"【本週任務】完成 1 分鐘自我介紹+本月總驗收。",a:"<b>自我介紹（計時練到 60 秒內）：</b>經驗主線（React / Vue / TS / 後台系統）→ 做過什麼 → 差異化能力（資料流追蹤）→ 下一步期望。<br><b>第 5 個月驗收：</b><ul><li>☐ 新版履歷完成</li><li>☐ 自我介紹 60 秒內講順</li><li>☐ 三個案例稿能口述</li><li>☐ 本月 20 題面試題每題能不看答案回答</li><li>☐ GitHub Demo + README 整理完畢</li></ul>" , opts: ["履歷完成、自我介紹 60 秒內講順、三個案例能口述、20 題面試題不看答案能回答、GitHub Demo 與 README 整理完畢","只要能完成自我介紹並上傳履歷至求職平台，即視為通過本月驗收標準","面試題背熟答案即可，不需要能夠口述案例或整理 GitHub 作品集","本月驗收重點是完成所有程式題的實作，口頭表達能力不在評估範圍內"], ans: 0},

  /* ====== 第 6 個月：投遞與修正 ====== */
  { m:6,w:1,d:1,t:"任務題",q:"打開人力銀行，用計畫裡的關鍵字搜出 10 個職缺。練習判斷：什麼叫「符合 60–70% 就可以投」？",a:"<b>判斷法：把 JD 的要求分三類：</b><ul><li><b>核心要求</b>（React / Vue、JS、API 串接）：你要會</li><li><b>加分要求</b>（Next.js、測試、CI/CD）：缺幾個沒關係</li><li><b>裝飾要求</b>（「熟悉各種前端技術」）：忽略</li></ul><b>結論：</b>核心符合 + 加分缺一些 = 投。JD 是廠商的「願望清單」，不是門檻。" , opts: ["所有要求一視同仁，全部符合才值得投遞","分核心、加分、裝飾三類，核心符合且加分缺幾個仍可投","只看加分要求，裝飾要求才是公司真正在意的","符合50%以下也可以投，反正面試再補強"], ans: 1},
  { m:6,w:1,d:2,t:"任務題",q:"挑一個你想投的職缺，針對它的 JD 客製你的履歷。要調整哪三個地方？",a:"<b>三處客製：</b><ul><li><b>技能排序</b>：JD 主打 Vue 就把 Vue 往前放</li><li><b>專案描述用詞</b>：對方 JD 出現的詞借來用</li><li><b>案例選擇</b>：金融業 → 放災演 / 文件案例；新創 → 放快速開發案例</li></ul><b>原則：</b>不是造假，是<b>調整聚光燈</b>。" , opts: ["重新設計履歷版面、加入圖表讓視覺更吸引人","把所有技能全部列出，讓人資有最完整的資訊","調整技能排序、用JD關鍵字改寫專案描述、依目標產業選案例","只改個人摘要，其他部分保持通用版本不動"], ans: 2},
  { m:6,w:1,d:3,t:"任務題",q:"建立你的投遞紀錄表。應該有哪些欄位？",a:"<b>建議欄位：</b><pre>| 公司 | 職缺 | 投遞日 | 來源 | 核心符合度 | 狀態 | 回應日 | 面試日 | 結果 | 備註 |</pre><b>狀態值：</b>已投 / 已讀 / 邀約 / 一面 / 二面 / offer / 婉拒 / 無回應。<b>為什麼重要：</b>回應率本身是訊號——投 20 個全無回應 = 履歷有問題；有面試但過不了 = 面試技巧或能力缺口。" , opts: ["只需記錄公司與職缺名稱，其他資訊靠記憶即可","投遞紀錄僅用於計算投了幾個，回應率高低不重要","記錄公司、職缺、投遞日、狀態、回應日、面試日、結果，回應率能診斷問題出在履歷或面試","回應率只反映市場景氣，與個人履歷品質無關"], ans: 2},
  { m:6,w:1,d:4,t:"任務題",q:"對著鏡子或錄音，計時做一次 1 分鐘自我介紹。用這份標準幫自己評分。",a:"<b>評分標準（每項 0–2 分，滿分 10）：</b><ul><li>時間控制：55–70 秒內結束</li><li>主線清楚：聽完知道你是「做後台系統的前端、強在資料流追蹤」</li><li>有具體詞：說出系統類型、技術棧</li><li>差異化：有講出別人少有的點</li><li>結尾有方向：說出想成為什麼、為何投這家</li></ul><b>低於 7 分：</b>修稿再錄一次。" , opts: ["開頭的自我介紹夠長夠詳細，讓面試官充分了解背景","技術能力描述要涵蓋所有用過的框架","結尾說出你想成為什麼以及為何投這家，展現主動性與方向感","語速要慢、咬字清晰，這是最常被忽略的評分項目"], ans: 2},
  { m:6,w:1,d:5,t:"任務題",q:"寫一段應徵信開頭，150 字以內，讓人資想往下看。",a:"<b>結構：你是誰一句 + 你和這職缺的交集一句 + 證據一句。</b><br><b>範例：</b>「您好，我是有後台管理系統開發經驗的前端工程師，主力 React / TypeScript。看到貴公司職缺重視資料密集的儀表板開發，與我日常負責的查詢、表格、API 串接工作高度相符。我習慣從 UI 事件追蹤至 API 與資料來源定位問題，相關作品整理於 GitHub，期待有機會進一步說明。」" , opts: ["先詳細列出過去所有工作經歷，讓人資了解完整背景","以誠懇的態度表達對公司的仰慕，建立情感連結","一句說明自己是誰（技術棧/方向）、一句點出與職缺的交集、一句附上具體證據","開頭先提薪資期望，節省雙方篩選時間"], ans: 2},
  { m:6,w:2,d:1,t:"任務題",q:"收到面試邀約了。列出你「面試前一天」的準備清單。",a:"<b>前一天清單：</b><ul><li>☐ 重讀 JD，預測會問的方向</li><li>☐ 查公司產品：實際打開他們的網站 / App 用 10 分鐘</li><li>☐ 複習自我介紹 + 三個案例（口述各一次）</li><li>☐ 掃過第 5 個月的 20 題面試題</li><li>☐ 準備 3 個反問問題</li><li>☐ 確認時間地點 / 視訊連結、測試鏡頭麥克風</li><li>☐ 作品集連結、履歷先開好</li></ul>" , opts: ["準備一份詳細的技術問題清單，確保能回答所有框架問題","提早一小時到場，熟悉環境與交通動線","實際打開公司產品使用10分鐘，能給出有溫度的具體回答","把履歷再讀一遍，確保能背出每個項目的細節"], ans: 2},
  { m:6,w:2,d:2,t:"觀念題",q:"「你有什麼問題想問我們嗎？」——準備 3 個好的反問問題，並說明什麼問題不要問。",a:"<b>好問題：</b><ul><li>「前端團隊目前的技術棧與分工方式？新人前三個月通常負責什麼？」</li><li>「團隊目前最想解決的前端技術挑戰是什麼？」</li><li>「程式碼有 code review 流程嗎？怎麼進行？」</li></ul><b>第一輪先別問：</b>薪資福利細節。<b>千萬別說：</b>「沒有問題」——等於說你沒做功課。" , opts: ["問薪資範圍與福利，這是最展現重視度的問題","說沒有問題，表示你已充分準備不需要額外資訊","問前端技術棧與分工、新人前三個月負責什麼，展現你在思考具體職責","問公司未來三年的發展方向，展現長遠眼光"], ans: 2},
  { m:6,w:2,d:3,t:"觀念題",q:"遇到現場寫題（白板題 / live coding），正確的答題流程是什麼？",a:"<b>五步流程：</b><ol style='margin-left:22px'><li><b>確認需求</b>：複述題目、問清邊界</li><li><b>講思路</b>：先說打算怎麼解</li><li><b>先求有再求好</b>：先寫出暴力解</li><li><b>自己測</b>：拿正常 + 邊界輸入走一遍</li><li><b>主動講優化</b>：時間複雜度、可讀性</li></ol>面試官評的是<b>過程與溝通</b>，全程出聲思考。" , opts: ["直接開始寫程式，越快寫出來越能展現實力","先確認需求、說思路、暴力解後自測邊界、再談優化，全程出聲思考","遇到不確定的地方就沉默思考，避免說錯被扣分","只要最終答案正確，過程不重要"], ans: 1},
  { m:6,w:2,d:4,t:"觀念題",q:"被問到不會的題目，怎麼回答最不扣分（甚至加分）？",a:"<b>三段式回答：</b><ol style='margin-left:22px'><li><b>誠實但不躺平</b>：「這個我沒有實際用過」</li><li><b>連結已知</b>：「不過聽起來和我用過的 ___ 在解類似問題…」</li><li><b>展現學習習慣</b>：「如果工作需要，我會先看官方文件做個小 demo 驗證」</li></ol>面試官在測的是你<b>遇到不會的東西時的反應</b>。" , opts: ["直接承認不會，保持誠實是最重要的事","嘗試硬答，就算不確定也要展現信心","誠實說沒用過、連結已知技術、說明會主動查官方文件做 demo 驗證","跳過這題請面試官換一個問題，以免浪費雙方時間"], ans: 2},
  { m:6,w:2,d:5,t:"觀念題",q:"被問「期望薪資多少」，怎麼回答？事前要做什麼功課？",a:"<b>事前功課：</b>查同職級行情，算出理想 / 滿意 / 底線。<b>回答策略：</b><ul><li>給<b>區間</b>：「期望月薪 70K–85K，依職責範圍與整體福利可以討論」</li><li>被壓價時回到價值：「我能獨立負責後台模組，希望薪資能反映這個能力」</li></ul><b>心法：</b>你是在<b>談</b>薪資，不是被動接受。" , opts: ["說「依公司規定」，展現彈性與配合度","給出單一明確數字，避免區間讓對方覺得你不夠果斷","給薪資區間，被壓價時回到自身價值並詢問其他福利空間","先問對方預算，再決定自己的期望薪資"], ans: 2},
  { m:6,w:3,d:1,t:"任務題",q:"剛結束一場面試（或模擬面試）。趁記憶猶新，用檢討格式完整記錄一次。",a:"<b>照計畫的格式逐項填：</b><pre>公司名稱：\n職缺名稱：\n面試日期：\n被問到的技術題：\n回答不好的地方：\n我不會的地方：\n下次要補強的內容：\n這間公司要求的能力：\n是否繼續投類似職缺：</pre><b>黃金時間：</b>面試結束 30 分鐘內記錄，過一晚會忘掉一半題目。" , opts: ["回家後好好休息，隔天再整理面試心得","等拿到結果後再回顧，有錄取才值得分析","面試結束30分鐘內記錄被問的技術題、回答不好的地方與補強方向","只記錄不會的題目，答對的題目不需要重複記錄"], ans: 2},
  { m:6,w:3,d:2,t:"觀念題",q:"怎麼把「面試被問倒的題目」變成你題庫的一部分？設計一個固定流程。",a:"<b>四步流程：</b><ol style='margin-left:22px'><li><b>收錄</b>：把題目原文寫進面試題庫</li><li><b>研究</b>：查資料寫出 5–8 行的參考答案，附程式例子</li><li><b>連結</b>：想一個自己工作 / Demo 中的對應實例</li><li><b>複誦</b>：三天後不看答案口述一次</li></ol>被問倒的題目是<b>市場直接告訴你的考試範圍</b>，比任何題庫都精準。" , opts: ["把題目截圖存起來，等累積到10題再一起研究","收錄→研究寫參考答案→連結個人實例→三天後不看答案口述一次","直接背誦標準答案，讓自己能快速流暢回答","只記錄概念題，程式題太難研究跳過即可"], ans: 1},
  { m:6,w:3,d:3,t:"任務題",q:"檢視你目前的技能缺口清單，用什麼標準排優先序？排出你的前三名。",a:"<b>排序公式：出現頻率 × 補強成本。</b><ul><li><b>高頻 + 低成本</b> → 第一優先（多場面試都問、一週能補）</li><li><b>高頻 + 高成本</b> → 排入下個月主題，每週固定推進</li><li><b>低頻 + 高成本</b> → 除非目標職缺明確要求，否則先放著</li></ul><b>判斷頻率的依據：</b>你的面試檢討紀錄——被問兩次以上就是高頻。" , opts: ["依個人興趣決定，選自己最想學的技能優先補強","全部技能同時補強，確保沒有明顯缺口","用出現頻率乘以補強成本排序，高頻低成本優先，低頻高成本最後","只補強上次面試被問倒的題目，其他不用管"], ans: 2},
  { m:6,w:3,d:4,t:"觀念題",q:"什麼訊號告訴你「該改履歷第二版了」？各種訊號分別對應什麼修改？",a:"<b>訊號 → 對策：</b><ul><li><b>投 15–20 個無回應</b> → 履歷第一屏問題 → 改技能區與摘要</li><li><b>有面試但常被問「你真的做過 X 嗎」</b> → 某段描述寫過頭 → 改成可被追問的具體寫法</li><li><b>面試官總是只聊到某一個專案</b> → 那段最吸引人 → 把同類經驗放大</li><li><b>邀約的職缺類型不是你想要的</b> → 履歷散發的訊號錯了 → 重新對齊目標職缺用詞</li></ul>" , opts: ["投了5個沒回應就要改履歷，不能等太久","面試次數多就代表履歷沒問題，不需要修改","投15–20個無回應改技能區與摘要；常被追問真實度改成具體可追問的寫法；邀約類型不對重新對齊目標職缺用詞","只要格式整齊專業，內容不用特別調整"], ans: 2},
  { m:6,w:3,d:5,t:"任務題",q:"寫兩封信的模板：(1) 面試後一週無消息的跟進信 (2) 婉拒 offer 但保持關係的信。",a:"<b>(1) 跟進信：</b>「您好，我是 X 月 X 日面試前端工程師職位的＿＿＿。想跟進目前的甄選進度，若需要補充作品或資訊請隨時告訴我。謝謝您！」——短、禮貌、不卑不亢。<br><br><b>(2) 婉拒信：</b>「非常感謝貴公司的肯定與 offer。經過審慎考量，我決定接受另一個更符合目前職涯規劃的機會。面試過程中與團隊的交流讓我收穫很多，希望未來有機會合作。」" , opts: ["跟進信要詳細解釋你的能力，婉拒信要說明為什麼不選這家","跟進信等兩週再發，婉拒時直接不回應即可","跟進信簡短禮貌不卑不亢；婉拒信感謝肯定、說明接受其他機會、保持正面關係","跟進信直接詢問為何沒有回應，婉拒時比較兩家薪資讓對方知道原因"], ans: 2},
  { m:6,w:4,d:1,t:"任務題",q:"設計你的每週投遞節奏：5–10 個職缺怎麼分配到一週裡？搭配原本的學習節奏怎麼調整？",a:"<b>建議節奏：</b><ul><li><b>週日</b>：搜尋 + 篩選本週要投的職缺（30 分）</li><li><b>週一、三</b>：各投 2–3 個，每個花 10 分鐘做履歷微客製</li><li><b>週二、四</b>：原本的實作練習改為「補強面試檢討出的缺口」</li><li><b>週五</b>：更新紀錄表、整理本週面試檢討</li></ul>" , opts: ["週一早上搜尋，趁人資剛上班最快看到你的應徵","每天持續搜尋，確保不錯過任何新職缺","週日搜尋篩選、週一三各投2–3個並微客製、週五更新紀錄表與面試檢討","只在平日午休時間投遞，避免在工作日被現任公司發現"], ans: 2},
  { m:6,w:4,d:2,t:"任務題",q:"把你累積的面試題整理成一份「個人面試題庫」。設計它的結構。",a:"<b>建議結構：</b><pre>分類：JS / React / TS / 實務 / 人格特質\n每題欄位：\n- 題目原文\n- 被問的公司與次數\n- 我的參考答案（5–8 行）\n- 對應的個人實例\n- 掌握度：✅ 能流暢回答 / 🔶 需要看稿 / ❌ 還不會</pre><b>使用方式：</b>每次面試前掃 🔶 和 ❌；每次面試後新增與更新次數。" , opts: ["只記題目原文和參考答案，其他欄位增加維護負擔","以考試難度分級，簡單/中等/困難三級即可","記錄題目原文、被問公司與次數、參考答案、對應個人實例、掌握度三級，面試前掃未掌握的題目","只記錄被問超過兩次的題目，一次性問題不值得建檔"], ans: 2},
  { m:6,w:4,d:3,t:"觀念題",q:"假設你同時拿到兩個 offer，要用哪些維度比較？只比薪水會漏掉什麼？",a:"<b>比較維度：</b><ul><li><b>薪酬全貌</b>：月薪 × 保障月數 + 獎金 + 加班制度</li><li><b>技術成長</b>：技術棧新舊、有沒有 code review</li><li><b>職責範圍</b>：是「獨立負責模組」還是「只切版改畫面」</li><li><b>團隊與主管</b>：工程文化</li><li><b>履歷價值</b>：兩年後這段經歷讓你的下一步更值錢嗎？</li></ul>" , opts: ["選薪資較高的那個，金錢是最客觀的衡量標準","選規模較大的公司，大公司資源多成長較快","考量「履歷價值」——兩年後這段經歷是否讓下一步更值錢，包含職責範圍與技術成長","選通勤時間較短的，工作生活平衡最重要"], ans: 2},
  { m:6,w:4,d:4,t:"任務題",q:"練習談薪：寫出三句你真的講得出口的談薪語句（開價、被壓價回應、爭取空間）。",a:"<b>範例：</b><ul><li><b>開價</b>：「我的期望是月薪 75K 到 85K，這是參考我能獨立負責後台模組的能力與市場行情。」</li><li><b>被壓價</b>：「我理解預算有考量。如果月薪到不了這個區間，想了解獎金、調薪機制或職級上有沒有空間？」</li><li><b>爭取</b>：「如果能到 80K，我可以這週就給答覆。」</li></ul><b>心法：</b>開完價就停，不要急著自己降價。" , opts: ["開價後主動說明可以接受更低，展現彈性增加錄取機會","開完價立刻詢問對方能給多少，掌握主導權","開完價後停下來等對方回應，被壓價時先問福利與調薪空間而非直接降月薪","多開幾個備選方案，讓對方從中選擇"], ans: 2},
  { m:6,w:4,d:5,t:"任務題",q:"【六個月總驗收】對照整份計畫，做最終檢查。",a:"<b>最終清單：</b><ul><li>☐ JS / TS / React 主線達到檢查表目標分數</li><li>☐ 一個完整 CRUD 後台 Demo + README 在 GitHub 上</li><li>☐ 3 個七段俱全、能口述的工作案例</li><li>☐ 新版履歷（含案例化描述）+ 客製化流程</li><li>☐ 60 秒自我介紹 + 個人面試題庫</li><li>☐ 投遞紀錄表運轉中、面試檢討有累積</li><li>☐ 我知道市場在問什麼、我卡在哪、下一步補什麼</li></ul><b>然後回頭看那句目標：</b>「從會改畫面的人，變成能獨立負責後台模組、能從 UI 追到 API 與資料來源的前端工程師。」🌊" , opts: ["通過所有技術面試題目且沒有答錯任何一題","累積超過50個面試邀約並拿到至少一個offer","3個案例能口述、完整CRUD Demo在GitHub、履歷與投遞紀錄表運轉中、面試題庫累積、清楚知道市場缺口與下一步","熟記所有前端技術文件並能背誦API用法"], ans: 2},
];

